const database_2023=[{title:"Usos de la membrana amni\xf3tica para tratamientos m\xe9dicos",short_name:"Usos de la membrana amni\xf3tica para tratamientos m\xe9dicos",url:"https://uncinnova.unc.edu.ar/usos-de-la-membrana-amniotica-para-tratamientos-medicos/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/11/portada-para-web-IMG_0088.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Salud humana",year:"2023",position:null,ua:["Laboratorio de Hemoderivados UNC"],team:["Cecilia Sobrero"],desc:"El Banco de Tejido de Membrana Amni\xf3tica del Laboratorio de Hemoderivados de la UNC procesa, preserva y distribuye membranas obtenidas de donaciones voluntarias de ces\xe1reas programadas. El tejido, completamente natural, posee propiedades antiinflamatorias, analg\xe9sicas, antimicrobianas y regenerativas. Se aplica en tratamientos de pie diab\xe9tico, oftalmolog\xeda, odontolog\xeda, ginecolog\xeda, traumatolog\xeda, dermatolog\xeda, cirug\xeda general y neurocirug\xeda, con el prop\xf3sito de ofrecer una alternativa terap\xe9utica de alta calidad a menor costo que otras opciones disponibles."},{title:"Desarrollo de un material alternativo para Impresi\xf3n 3D",short_name:"Material alternativo para Impresi\xf3n 3D",url:"https://uncinnova.unc.edu.ar/desarrollo-de-un-material-alternativo-para-impresion-3d-2/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/4-BIOECONOMIA-PORTADA.jpg",category:"Producto, proceso o servicio innovador",topic:"Bioeconom\xeda",year:"2023",position:null,ua:["Facultad de Ciencias Qu\xedmicas"],team:["Marisa Martinelli","Mariana Nu\xf1ez","Ana Clara Picinato"],desc:"El proyecto busca el desarrollo de materiales h\xedbridos para impresi\xf3n 3D, a partir de \xe1cido polil\xe1ctico (PLA)  y otros pol\xedmeros accesibles desde el medio local. El objetivo es reemplazar parte de la importaci\xf3n de la materia prima y reducir costos."},{title:"Mura, colecci\xf3n de joyas urbanas",short_name:"Mura, colecci\xf3n de joyas urbanas",url:"https://uncinnova.unc.edu.ar/mura-coleccion-de-joyas-urbanas/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/Copia-de-DSC_4687-copia-1-scaled-1.jpg",category:"Producto, proceso o servicio innovador",topic:"Conservaci\xf3n de la biodiversidad y cambio clim\xe1tico",year:"2023",position:null,ua:["Facultad de Arquitectura, Urbanismo y Dise\xf1o"],team:["Miguel Eduardo Tesino","Katrina Abril Wysoki"],desc:"Mura es una colecci\xf3n de joyer\xeda que transforma materiales reciclados mediante \xabupcycling\xbb en piezas de dise\xf1o urbano \xfanicas y de alta calidad. El prop\xf3sito es demostrar que los procesos productivos sostenibles pueden generar objetos de valor, promoviendo la econom\xeda circular y la conciencia ambiental en la industria del dise\xf1o y la joyer\xeda."},{title:"Grito: colecci\xf3n de joyer\xeda que alza la voz del yaguaret\xe9",short_name:"Grito | Joyer\xeda que alza la voz del yaguaret\xe9",url:"https://uncinnova.unc.edu.ar/grito-coleccion-de-joyeria-que-se-propone-hacer-escuchar-la-voz-del-yaguarete/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/IMG-20220627-WA0025.jpg",category:"Producto, proceso o servicio innovador",topic:"Conservaci\xf3n de la biodiversidad y cambio clim\xe1tico",year:"2023",position:null,ua:["Facultad de Arquitectura, Urbanismo y Dise\xf1o"],team:["Nancy Farias"],desc:"GRITO es una colecci\xf3n de seis piezas de joyer\xeda que representan simb\xf3licamente la situaci\xf3n cr\xedtica del yaguaret\xe9 en Argentina. Cada una trabaja un concepto orientado a generar la toma de conciencia y movilizar la participaci\xf3n activa de la sociedad en su protecci\xf3n. La propuesta puede extrapolarse como medio art\xedstico para visibilizar otras especies en peligro."},{title:"Indicadores de calidad ambiental basado en informaci\xf3n satelital hiperespectral",short_name:"Calidad ambiental basada en informaci\xf3n satelital",url:"https://uncinnova.unc.edu.ar/desarrollo-y-modelado-de-indicadores-de-calidad-ambiental-de-los-recursos-hidricos-a-partir-de-informacion-satelital-hiperespectral/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/portada.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Conservaci\xf3n de la biodiversidad y cambio clim\xe1tico",year:"2023",position:null,ua:["Instituto Gulich"],team:["Anabella Ferral","Giuliana Beltramone","Marcelo Scavuzzo","Alba Germ\xe1n","Victor Gauto","Mat\xedas Bonansea","Sof\xeda Pana","Francisco Nemi\xf1a"],desc:"Este proyecto aplica im\xe1genes satelitales hiperespectrales para monitorear la eutrofizaci\xf3n en embalses como el San Roque e  identificar impurezas que aceleran el derretimiento de mantos n\xedveos en la Patagonia. Es una \xe1rea de vacancia absoluta en Argentina. El fin es generar soluciones de monitoreo ambiental de vanguardia para la gesti\xf3n de recursos h\xeddricos y la evaluaci\xf3n del cambio clim\xe1tico."},{title:"Relevamiento de \xe1reas campesinas para la soberan\xeda alimentaria",short_name:"\xc1reas campesinas para la soberan\xeda alimentaria",url:"https://uncinnova.unc.edu.ar/relevamiento-de-areas-campesinas-para-la-soberania-alimentaria-en-los-banados-del-rio-dulce-y-mar-de-ansenuza-2016-2020-desde-una-perspectiva-integral-de-derechos-humanos/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/portada-rancho.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Conservaci\xf3n de la biodiversidad y cambio clim\xe1tico",year:"2023",position:null,ua:["Facultad de Ciencias Sociales"],team:["Lucia del Rosario Lerda","Antonella Bainotti","Alicia Barchuk","Mariana Gamboa","Miguel Genti","Victoria Gauna","Gala Aznarez Carini","Gabriela Calder\xf3n","Victoria \xc1lvarez Moyano","Javier Ana","Yanina Reta","Andrea Quiroga","Martin Ferrer","Danielle Lucia","Lourdes Lucero","Sof\xeda Hern\xe1ndez","Andrea Rocha","Dante Barrera","Roberto Carlos Soria","Marina Mansilla","Zulema \xc1ngulo","Guillermo Diaz","Estela Barrera"],desc:"Esta iniciativa sistematiza informaci\xf3n sobre las pr\xe1cticas productivas y la situaci\xf3n ambiental de territorios campesinos ind\xedgenas en el humedal Ansenuza, de C\xf3rdoba. Para ello, aplica la Investigaci\xf3n Acci\xf3n, con participaci\xf3n directa de las comunidades. El objetivo es generar demandas concretas ante el Estado para la protecci\xf3n ambiental y el acceso a derechos de quienes habitan ancestralmente esa regi\xf3n, amenazada por la privatizaci\xf3n de tierras."},{title:"An\xe1lisis de la eficiencia econ\xf3mica y ambiental del transporte p\xfablico el\xe9ctrico",short_name:"Eficiencia del transporte p\xfablico el\xe9ctrico",url:"https://uncinnova.unc.edu.ar/analisis-economico-sobre-la-implementacion-del-transporte-publico-electrico-en-la-ciudad-de-cordoba/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/index-1.jpeg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Conservaci\xf3n de la biodiversidad y cambio clim\xe1tico",year:"2023",position:null,ua:["Facultad de Ciencias Exactas, F\xedsicas y Naturales"],team:["Ignacio Collomb","Adriel Pronotti"],desc:"Este estudio eval\xfaa la viabilidad de reemplazar los colectivos diesel de C\xf3rdoba por unidades el\xe9ctricas, comparando tecnolog\xedas disponibles, costos de implementaci\xf3n, mantenimiento y el beneficio econ\xf3mico del ahorro en emisiones de CO₂. El prop\xf3sito es aportar informaci\xf3n t\xe9cnica y econ\xf3mica para preparar a la ciudad ante la transici\xf3n hacia tecnolog\xedas limpias de transporte p\xfablico."},{title:"Desarrollo de una plataforma m\xf3vil para medici\xf3n de precipitaciones con disdr\xf3metro",short_name:"Plataforma m\xf3vil para medici\xf3n de precipitaciones",url:"https://uncinnova.unc.edu.ar/diseno-y-desarrollo-de-una-plataforma-movil-para-medicion-de-precipitaciones-con-disdrometro-en-la-provincia-de-cordoba-argentina/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/IMG_6445-768x1024-1.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Conservaci\xf3n de la biodiversidad y cambio clim\xe1tico",year:"2023",position:null,ua:["Facultad de Ciencias Exactas, F\xedsicas y Naturales"],team:["Juan Pablo Guida","Pedro Ruiz D\xedaz","Rom\xe1n Martino","Andr\xe9s Rodr\xedguez","Ricardo Ingaramo","Edgardo Pierobon","Ignacio Montamat","Mat\xedas Su\xe1rez","Roberto G\xf3mez","Roland Del \xc1guila","Joaqu\xedn Busignani Hiruela","\xc9rica D\xedaz","Pedro Ortolani"],desc:"Este proyecto dise\xf1\xf3 e implement\xf3 una plataforma m\xf3vil que transporta un disdr\xf3metro Ott Parsivel2 de \xfaltima generaci\xf3n, montado en una camioneta 4\xd74 con alimentaci\xf3n solar aut\xf3noma y transmisi\xf3n de datos en tiempo real. El dispositivo es \xfanico en Argentina por su capacidad para medir tama\xf1o, velocidad y densidad de hidrometeoros, con alta resoluci\xf3n temporal, mientras sigue el fen\xf3meno en zonas de dif\xedcil acceso. Complementa el trabajo del Radar Meteorol\xf3gico Argentino (RMA1) de la UNC."},{title:"Caracterizaci\xf3n del flujo en una c\xe1mara de cloraci\xf3n en el tratamiento de aguas residuales",short_name:"Caracterizaci\xf3n del flujo en el tratamiento de aguas residuales",url:"https://uncinnova.unc.edu.ar/caracterizacion-del-flujo-en-una-camara-de-cloracion-en-el-tratamiento-de-aguas-y-aguas-residuales-utilizando-modelos-fisicos-y-numericos-a-escala-de-laboratorio/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/Figure_2-min.png",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Conservaci\xf3n de la biodiversidad y cambio clim\xe1tico",year:"2023",position:null,ua:["Facultad de Ciencias Exactas, F\xedsicas y Naturales"],team:["Di Bu\xf2 Melina","Molina Sofia","Ragessi Ivan Matias","Hillman Gerardo","Garc\xeda Carlos Marcelo","Rodriguez Andr\xe9s"],desc:"Este proyecto combina modelos f\xedsicos a escala de laboratorio con fluidodin\xe1mica computacional (CFD) para optimizar el dise\xf1o hidr\xe1ulico de las c\xe1maras de contacto de cloraci\xf3n en plantas de tratamiento de agua. Busca mejorar la eficiencia de la desinfecci\xf3n en plantas existentes y generar informaci\xf3n de dise\xf1o v\xe1lida para nuevas instalaciones."},{title:"Proyecto PREVENIR: sistema de alerta temprana para inundaciones urbanas",short_name:"PREVENIR | Sistema de alerta temprana para inundaciones",url:"https://uncinnova.unc.edu.ar/proyecto-prevenir-sistema-de-alerta-temprana-para-inundaciones-urbanas-en-argentina/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/IMG_4025.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Conservaci\xf3n de la biodiversidad y cambio clim\xe1tico",year:"2023",position:null,ua:["Facultad de Ciencias Exactas, F\xedsicas y Naturales"],team:["Carlos Marcelo Garc\xeda","Jos\xe9 Manuel Diaz Lozada","Antoine Patalano","Sebastian Lopez","Leandro Mass\xf3","Andr\xe9s Portigliatti","Ana Heredia Ligorria","Roc\xedo Bianchi","Joaqu\xedn Segura Ellias"],desc:"PREVENIR es una colaboraci\xf3n argentino-japonesa que utiliza t\xe9cnicas de asimilaci\xf3n de datos en la supercomputadora Fugaku para desarrollar un sistema de pron\xf3stico de lluvias extremas e inundaciones urbanas. El trabajo se enfoca en dos cuencas vulnerables: Sarand\xed-Santo Domingo y el r\xedo Suqu\xeda en C\xf3rdoba. El fin es emitir alertas tempranas a la comunidad para mitigar el riesgo h\xeddrico con al menos 24 horas de anticipaci\xf3n."},{title:"VARIAL 1500w: motocicleta el\xe9ctrica urbana",short_name:"VARIAL 1500w | Motocicleta el\xe9ctrica urbana",url:"https://uncinnova.unc.edu.ar/varial-1500w-motocicleta-electrica-urbana/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/VARIAL-1500w-prototipo-1.jpeg",category:"Producto, proceso o servicio innovador",topic:"Conservaci\xf3n de la biodiversidad y cambio clim\xe1tico",year:"2023",position:null,ua:["Facultad de Arquitectura, Urbanismo y Dise\xf1o"],team:["Amuch\xe1stegui Juan Cruz","Nieto Matias Ariel"],desc:"VARIAL 1500w es una motocicleta el\xe9ctrica de configuraci\xf3n modular dise\xf1ada para fabricarse con geometr\xedas y componentes simples, disponibles en la industria local. Su dise\xf1o permite adaptarla entre distintos usos —transporte de pasajeros y utilitario— para ampliar su mercado. La propuesta apunta a eliminar emisiones y contaminaci\xf3n sonora, mediante una alternativa m\xe1s eficiente y segura para la movilidad urbana."},{title:"Generador el\xe9ctrico solar para autom\xf3viles con almacenamiento de energ\xeda y conexi\xf3n domiciliaria",short_name:"Generador el\xe9ctrico solar para autom\xf3viles",url:"https://uncinnova.unc.edu.ar/generador-electrico-solar-para-automoviles-con-almacenamiento-de-energia-y-conexion-domiciliaria/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/4-conservacion-generador2-1.jpg",category:"Producto, proceso o servicio innovador",topic:"Conservaci\xf3n de la biodiversidad y cambio clim\xe1tico",year:"2023",position:null,ua:["Facultad de Arquitectura, Urbanismo y Dise\xf1o"],team:["Alexis Tapia"],desc:"El generador que se acopla a veh\xedculos y aprovecha la energ\xeda cin\xe9tica de su movimiento para producir electricidad, almacenarla y luego inyectarla a la red domiciliaria para iluminaci\xf3n. Permite reducir la huella de carbono de los veh\xedculos a combusti\xf3n y proveer acceso a energ\xeda el\xe9ctrica renovable en hogares, especialmente en zonas con red inestable o inaccesible."},{title:"Pron\xf3stico de calidad del aire a partir de incendios",short_name:"Pron\xf3stico de calidad del aire a partir de incendios",url:"https://uncinnova.unc.edu.ar/pronostico-de-calidad-del-aire-a-partir-de-incendios/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/Pronostico.png",category:"Producto, proceso o servicio innovador",topic:"Conservaci\xf3n de la biodiversidad y cambio clim\xe1tico",year:"2023",position:null,ua:["Instituto Gulich"],team:["Mar\xeda Fernanda Garc\xeda Ferreyra","Gabriele Curci","Miguel Vargas Calder\xf3n","Andr\xe9s Lighezzolo","Carlos Marcelo Scavuzzo"],desc:"Esta iniciativa implementa en Argentina -por primera vez, a nivel operativo- un sistema de modelado que combina inventarios de emisiones, datos satelitales diarios de incendios y modelos num\xe9ricos de transporte qu\xedmico para producir mapas geolocalizados de concentraci\xf3n de contaminantes y un \xedndice de calidad del aire con resoluci\xf3n horaria y hasta 24 horas de pron\xf3stico. Sus productos est\xe1n disponibles en formatos interoperables para organismos ambientales provinciales y nacionales."},{title:"Prevenci\xf3n de incendios a trav\xe9s de informaci\xf3n satelital en el Parque Nacional Quebrada del Condorito",short_name:"Prevenci\xf3n de incendios a trav\xe9s de informaci\xf3n satelital",url:"https://uncinnova.unc.edu.ar/amenaza-de-incendios-en-el-parque-nacional-quebrada-del-condorito/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/Figura3_Probabilidad-de-incendios-y-probabilidad-de-incendios-de-alta-intensidad-en-el-PNQC-1024x724-1.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Conservaci\xf3n de la biodiversidad y cambio clim\xe1tico",year:"2023",position:null,ua:["Facultad de Ciencias Exactas, F\xedsicas y Naturales","Instituto Gulich","Consejo Nacional de Investigaciones Cient\xedficas y T\xe9cnicas (CONICET)"],team:["Juan Pablo Arga\xf1araz","Alan Ager","Cecilia Naval Fern\xe1ndez","Max Nielsen-Pincus","Cody Evers","Marcelo Scavuzzo","Laura Bellis"],desc:"Este trabajo simula 30.000 incendios bajo distintos escenarios de viento en el Parque Nacional Quebrada del Condorito, usando modelos de combustibles locales construidos con im\xe1genes satelitales. El fin es obtener mapas de amenaza —probabilidad, intensidad y tama\xf1o potencial— para orientar la gesti\xf3n del riesgo de incendios en una zona protegida que abastece de agua potable a gran parte de la provincia de C\xf3rdoba."},{title:"Cambios en el uso del suelo y diversidad de aves en los bosques subtropicales",short_name:"Uso del suelo y diversidad de aves en bosques subtropicales",url:"https://uncinnova.unc.edu.ar/cambios-en-el-uso-del-suelo-y-diversidad-de-aves-en-los-bosques-subtropicales-el-desarrollo-urbano-como-factor-subyacente/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/DSC_0167-01-683x1024-1.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Conservaci\xf3n de la biodiversidad y cambio clim\xe1tico",year:"2023",position:null,ua:["Instituto de altos estudios espaciales \xabMario Gulich\xbb&nbsp;","Universidad Nacional de C\xf3rdoba&nbsp;","Instituto Nacional de Tecnolog\xeda Agropecuaria"],team:["Luna Silvetti","Laura Bellis","Julieta Arcamone","Paula Alvarez","Cecilia Naval","Juan Arga\xf1araz","Carolina Baldini"],desc:"Consiste en la combinaci\xf3n de mapas satelitales de cobertura con datos de campo sobre estructura vegetal y presencia de aves. La finalidad es identificar los factores biof\xedsicos y antr\xf3picos que determinan la diversidad de comunidades aviares en el Bosque Serrano. En ese sentido, apunta a brindar informaci\xf3n cient\xedfica que oriente la planificaci\xf3n territorial para la conservaci\xf3n del paisaje y la biodiversidad frente al avance urbano y agr\xedcola."},{title:"Experiencia 70/30: Un modelo de gesti\xf3n del espacio p\xfablico urbano enfocado al ocio y turismo de cercan\xeda",short_name:"Experiencia 70/30: Un modelo de gesti\xf3n del espacio p\xfablico",url:"https://uncinnova.unc.edu.ar/experiencia-70-30-un-modelo-de-gestion-del-espacio-publico-urbano-enfocado-al-ocio-y-turismo-de-cercania/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/exp-cul2-1.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Transformaci\xf3n tecnol\xf3gica",year:"2023",position:null,ua:["Facultad de Arquitectura, Urbanismo y Dise\xf1o","Consejo Nacional de Investigaciones Cient\xedficas y T\xe9cnicas (CONICET)"],team:["Sebasti\xe1n Cortez Oviedo","Ignacio Herrero","Claudia M. Sosa","Federico Talone"],desc:"Experiencia 70/30 es una aplicaci\xf3n m\xf3vil georreferenciada que permite —a vecinos, empresas privadas y organismos estatales— crear recorridos narrativos personalizados en la ciudad de C\xf3rdoba, orientados al ocio y el turismo de cercan\xeda. La propuesta integra a los tres actores clave del ecosistema urbano (Estado, sector privado y sociedad civil) en la generaci\xf3n de experiencias culturales, ecol\xf3gicas y recreativas m\xe1s participativas, sostenibles e inclusivas."},{title:"Transceptor digital multiprop\xf3sito para la correcci\xf3n de imperfecciones de los pulsos de Resonancia Magn\xe9tica Nuclear",short_name:"Transceptor digital multiprop\xf3sito para RMN",url:"https://uncinnova.unc.edu.ar/desarrollo-de-un-transceptor-digital-multiproposito-para-correccion-de-imperfecciones-en-la-calidad-de-los-pulsos-de-resonancia-magnetica-nuclear/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/Transceptor-digital-multiproposito-768x1024-1.jpg",category:"Producto, proceso o servicio innovador",topic:"Transformaci\xf3n tecnol\xf3gica",year:"2023",position:null,ua:["Facultad de Matem\xe1tica, Astronom\xeda y F\xedsica"],team:["Guillermo Hernan Bustos","Hector Hugo Segnorile"],desc:"Consiste en la implementaci\xf3n de algoritmos propios en la plataforma de radiofrecuencia y control digital de un equipo de Resonancia Magn\xe9tica Nuclear (RMN), para detectar y corregir autom\xe1ticamente imperfecciones en los pulsos de salida. La meta es aumentar la precisi\xf3n de las t\xe9cnicas de RMN en investigaci\xf3n b\xe1sica, con potencial de aplicaci\xf3n en im\xe1genes por resonancia magn\xe9tica (MRI), radares y sistemas de comunicaciones."},{title:"Programa de Innovaci\xf3n y desarrollo tecnol\xf3gico (PIDT)",short_name:"Programa de Innovaci\xf3n y desarrollo tecnol\xf3gico",url:"https://uncinnova.unc.edu.ar/programa-de-innovacion-y-desarrollo-tecnologico/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/23-TRANSF-TECNO-PIDT-1.jpg",category:"Producto, proceso o servicio innovador",topic:"Transformaci\xf3n tecnol\xf3gica",year:"2023",position:null,ua:["Secretar\xeda de Extensi\xf3n UNC"],team:["Mar\xeda Zoe Maldonado V\xe9lez","Jeanette Candela Peralta Arias","Juan Ignacio Sipowicz"],desc:"El PIDT de la Secretar\xeda de Extensi\xf3n de la UNC articula un laboratorio de dise\xf1o e impresi\xf3n 3D con un programa de desarrollo de software para ofrecer soluciones tecnol\xf3gicas a la sociedad civil, instituciones y empresas. Entre sus aplicaciones se cuentan sistemas de gesti\xf3n vecinal, plataformas educativas, alarmas vecinales y herramientas de intercambio laboral. Es una l\xednea de trabajo dirigida a democratizar el acceso a tecnolog\xeda digital desde la universidad p\xfablica."},{title:"Joyas con relato: una propuesta de joyer\xeda sostenible y personalizada",short_name:"Joyas con relato | Joyer\xeda sostenible y personalizada",url:"https://uncinnova.unc.edu.ar/joyas-con-relato-una-propuesta-innovadora-de-joyeria-sostenible-y-personalizada/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/IMG_8001.jpg",category:"Producto, proceso o servicio innovador",topic:"Transformaci\xf3n tecnol\xf3gica",year:"2023",position:null,ua:["Facultad de Arquitectura, Urbanismo y Dise\xf1o"],team:["Laura Ferrari"],desc:"Joyas con Relato dise\xf1a piezas de joyer\xeda personalizadas a partir de materiales que ya no est\xe1n en uso, reutiliz\xe1ndolos y revaloriz\xe1ndolos. El proceso parte de una investigaci\xf3n del usuario —su estilo de vida, contexto y preferencias— para crear una colecci\xf3n \xfanica y entregada en packaging exclusivo. El fin es ofrecer una alternativa a la joyer\xeda convencional que combine personalizaci\xf3n, sostenibilidad y respeto por el medio ambiente."},{title:"ARGO: Sistema de tambo modular para una producci\xf3n lechera eficiente",short_name:"ARGO | Sistema de tambo modular",url:"https://uncinnova.unc.edu.ar/argo-sistema-de-tambo-modular-para-una-produccion-lechera-eficiente/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/20221014113732longevidadvacas.jpg",category:"Producto, proceso o servicio innovador",topic:"Transformaci\xf3n tecnol\xf3gica",year:"2023",position:null,ua:["Facultad de Arquitectura, Urbanismo y Dise\xf1o"],team:["Guillermo Gabriel Amestoy","Franco Dar\xedo Perrone Fogliatto"],desc:"ARGO es un sistema de tambo modular y portable fabricado industrialmente, que resuelve tres problemas centrales del sector: la necesidad de posesi\xf3n definitiva del suelo, el crecimiento progresivo de la instalaci\xf3n y la migraci\xf3n tecnol\xf3gica del equipamiento. Puede trasladarse, revenderse y adaptarse a distintas escalas productivas. Est\xe1 pensado para transformar la cadena de valor lechera con una instalaci\xf3n eficiente, competitiva econ\xf3micamente y sin las limitaciones de los tambos convencionales."},{title:"Tutor de Tambo: sistema constructivo para el crecimiento de instalaciones l\xe1cteas de calidad",short_name:"Tutor de Tambo | Sistema para instalaciones l\xe1cteas",url:"https://uncinnova.unc.edu.ar/tutor-de-tambo-sistema-constructivo-para-el-crecimiento-de-instalaciones-lacteas-de-calidad/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/A3-Linea-media-copia.jpg",category:"Producto, proceso o servicio innovador",topic:"Transformaci\xf3n tecnol\xf3gica",year:"2023",position:null,ua:["Facultad de Arquitectura, Urbanismo y Dise\xf1o"],team:["Luciana Dutari","Agust\xedn Berta"],desc:"Sistema constructivo modular que traslada las prestaciones de tambos convencionales a componentes reproducibles industrialmente, de r\xe1pido montaje y costo competitivo. Su dise\xf1o apunta espec\xedficamente a peque\xf1os y medianos productores que quedan fuera del alcance de las soluciones comerciales disponibles. Busca mejorar la eficiencia productiva, as\xed como el bienestar animal y laboral, sin depender de obras costosas y de dif\xedcil ampliaci\xf3n."},{title:"Interior al desnudo: una colecci\xf3n de joyer\xeda que refleja tu personalidad",short_name:"Interior al desnudo | Colecci\xf3n de joyer\xeda",url:"https://uncinnova.unc.edu.ar/interior-al-desnudo-una-coleccion-de-joyeria-que-refleja-tu-personalidad/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/11/Interior-al-desnudo-scaled.jpg",category:"Producto, proceso o servicio innovador",topic:"Transformaci\xf3n tecnol\xf3gica",year:"2023",position:null,ua:["Facultad de Arquitectura, Urbanismo y Dise\xf1o"],team:["Sara Bossa"],desc:"\xabInterior al desnudo\xbb combina materiales artesanales e industriales —acr\xedlico, plata, bronce y resina— para crear piezas de joyer\xeda \xfanicas que generan una experiencia sensorial a trav\xe9s de texturas, colores y emociones. La propuesta apunta a ofrecer piezas que expresen la personalidad del portador, aptas tanto para el uso cotidiano como para ocasiones formales, con una manufactura \xe1gil que une lo artesanal con lo industrializado."},{title:"ROOFTI | Sistema constructivo sostenible y eficiente basado en tecnolog\xeda CNC",short_name:"ROOFTI | Sistema constructivo basado en CNC",url:"https://uncinnova.unc.edu.ar/roofti-un-sistema-constructivo-sostenible-y-eficiente-basado-en-tecnologia-cnc/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/05-RENDER.jpg",category:"Producto, proceso o servicio innovador",topic:"Transformaci\xf3n tecnol\xf3gica",year:"2023",position:null,ua:["Facultad de Arquitectura, Urbanismo y Dise\xf1o"],team:["Manuel Guzm\xe1n","Francisco Ruiz","Gabriel Zabala","Juan Accotto"],desc:"ROOFTI es un sistema habitable modular fabricado con materiales sostenibles, uniones encastrables y tecnolog\xeda CNC. Est\xe1 pensado para construir de forma r\xe1pida, econ\xf3mica y sin mano de obra especializada. Sus m\xf3dulos se fraccionan para el transporte, se montan f\xe1cilmente y pueden instalarse en contextos muy variados: viviendas temporales, espacios educativos, alojamientos tur\xedsticos o situaciones de emergencia."},{title:"Desarrollo de una fuente de corriente para resonancia magn\xe9tica nuclear por ciclado r\xe1pido de campo",short_name:"Fuente de corriente para RMN",url:"https://uncinnova.unc.edu.ar/prueba-de-concepto-de-una-fuente-de-corriente-para-aplicaciones-de-resonancia-magnetica-nuclear-por-ciclado-rapido-de-campo/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/Prueba-de-concepto-de-una-fuente-de-corriente-1024x578-1.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Transformaci\xf3n tecnol\xf3gica",year:"2023",position:null,ua:["Facultad de Matem\xe1tica, Astronom\xeda y F\xedsica","CONICET"],team:["Mar\xeda Delfina V\xe9lez Ibarra","Gonzalo Tom\xe1s Vodanovic","Gabriela Marta Peretti","Eduardo Abel Romero","Esteban Anoardo"],desc:"Este proyecto desarrolla una fuente de corriente para equipos de Resonancia Magn\xe9tica Nuclear por ciclado r\xe1pido de campo (FFC-NMR), capaz de generar un campo de 0,2T con un \xfanico transistor, operando en modo lineal y a baja tensi\xf3n. Incorpora tambi\xe9n un test peri\xf3dico para detectar fallas y proteger los equipos. La soluci\xf3n apunta a reducir costos y mejorar la confiabilidad de estos instrumentos utilizados en estudios de relaxometr\xeda."},{title:"Ibis SOS: sistema de alertas de seguridad ciudadana para la construcci\xf3n participativa de la seguridad",short_name:"Ibis SOS | Alerta de seguridad ciudadana",url:"https://uncinnova.unc.edu.ar/ibis-sos-un-sistema-de-alertas-de-seguridad-ciudadana-para-la-construccion-participativa-de-la-seguridad/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/11/Ibis-SOS.png",category:"Producto, proceso o servicio innovador",topic:"Transformaci\xf3n tecnol\xf3gica",year:"2023",position:null,ua:["Facultad de Comunicaci\xf3n Social"],team:["Federico Uceda","Marcelo Uceda"],desc:"Ibis SOS es una aplicaci\xf3n para vecinos y un panel de control municipal que centraliza alertas ante distintas situaciones de riesgo —desde delitos hasta emergencias m\xe9dicas o accidentes dom\xe9sticos— y las coordina con las fuerzas de seguridad y emergencias. Genera estad\xedsticas para mejorar la gesti\xf3n de los sucesos y dise\xf1ar estrategias territoriales. Su enfoque descentralizado y participativo lo distingue de otras soluciones de seguridad ciudadana disponibles."},{title:"Desarrollo de una vacuna contra la fasciolisis producida con prote\xednas recombinantes de la familia Kunitz",short_name:"Vacuna contra la fasciolisis",url:"https://uncinnova.unc.edu.ar/produccion-de-proteinas-recombinantes-de-la-familia-kunitz-para-el-desarrollo-de-una-vacuna-contra-fasciola-hepatica-en-ovinos/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/15-TRANSF-TECNO-VACUNA-OVINA-1.jpg",category:"Producto, proceso o servicio innovador",topic:"Transformaci\xf3n tecnol\xf3gica",year:"2023",position:null,ua:["Facultad de Ciencias Qu\xedmicas"],team:["Laura Cervi","Jos\xe9 Luis Barra","Mar\xeda Ahumada","Agustina Godino","Marilla Amaranto"],desc:"Este trabajo produce prote\xednas recombinantes de la familia Kunitz mediante tecnolog\xeda de ADN recombinante, formuladas con hidr\xf3xido de aluminio como adyuvante, para desarrollar una vacuna experimental contra *Fasciola hepatica* en ovinos. El prop\xf3sito es reducir la mortalidad aguda por esta enfermedad parasitaria hep\xe1tica, mejorar los \xedndices productivos del ganado —peso, pre\xf1ez, calidad de carne y lana— y hacer posible la producci\xf3n local a bajo costo."},{title:"LDSUS: combatiendo las floraciones algales en embalses con sensores remotos",short_name:"LDSUS | Combatiendo las floraciones algales",url:"https://uncinnova.unc.edu.ar/ldsus-desarrollo-y-aplicacion-de-sensores-remotos-para-monitoreo-y-control-de-floraciones-algales-en-embalses/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/dd69303f-e59b-41bc-8562-5312245c5995.jpg",category:"Producto, proceso o servicio innovador",topic:"Transformaci\xf3n tecnol\xf3gica",year:"2023",position:null,ua:["Facultad de Ciencias Exactas, F\xedsicas y Naturales"],team:["Andres Rodriguez","Jonathan Muchiut","Mariano Corral","Santiago Rodriguez Glez","Mauro Gaston","Guido Marconi","Pedro Ru\xedz","Florencia Romero","Aracelli Ferreira","Micaela Juaneda","Alberto Vitulich","Ronald Del Aguila","Silvana Alac","Valeria Ame","Maria Ines Rodriguez","Marcia Ruiz","Ana Laura Ruibal"],desc:"LDSUS integra sensores remotos pasivos y activos con modelado num\xe9rico 3D para monitorear en forma continua las floraciones de cianobacterias en embalses que proveen agua potable a C\xf3rdoba. Ya se instalaron tres sensores en embalses provinciales y se realizan experimentos de laboratorio con ultrasonido para identificar las condiciones ambientales que desencadenan y restringen los blooms. No existe en el pa\xeds otra integraci\xf3n tecnol\xf3gica similar aplicada a esta problem\xe1tica."},{title:"Taribe: Desarrollo de eventos virtuales con realidad virtual y tecnolog\xeda blockchain",short_name:"Taribe | Desarrollo de eventos virtuales",url:"https://uncinnova.unc.edu.ar/taribe-desarrollo-de-eventos-virtuales-con-realidad-virtual-y-tecnologia-blockchain/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/ALN03995.jpg",category:"Producto, proceso o servicio innovador",topic:"Transformaci\xf3n tecnol\xf3gica",year:"2023",position:null,ua:["Facultad de Ciencias Exactas, F\xedsicas y Naturales"],team:["Francisco Actis Danna","Rodrigo Alvarez Casa\xf1as","Gabriel Calvo"],desc:"Taribe es una agencia que dise\xf1a eventos virtuales corporativos, combinando realidad virtual para crear entornos inmersivos tipo metaverso y NFTs basados en blockchain para generar coleccionables digitales. Ofrece a las empresas experiencias sin limitaciones geogr\xe1ficas ni de capacidad, desde reuniones de networking hasta presentaciones de productos, galer\xedas de arte y lanzamientos. Ya trabaj\xf3 con empresas como Grupo Endeavor, Grupo Campari y LaBitconf."},{title:"Propuesta de sistemas seudo-satelitales para mejorar las funciones espaciales",short_name:"Sistemas seudo-satelitales",url:"https://uncinnova.unc.edu.ar/propuesta-de-sistemas-seudo-satelitales-para-mejorar-las-funciones-espaciales/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/sistemas-seudo-satelitales-compressed-scaled-1.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Transformaci\xf3n tecnol\xf3gica",year:"2023",position:null,ua:["Facultad de Ciencias Exactas, F\xedsicas y Naturales"],team:["Omar Elaskar","Jorge Garc\xeda","Mart\xedn Pilati","Carlos Vitulich","Enrique Clacagni","Leandro Alem","Martin Elaskar Plazas","Javier Elaskar Plazas"],desc:"Este proyecto propone el despliegue de globos estratosf\xe9ricos de vuelo libre en alturas superiores a 17 km como Sistemas Seudo-Satelitales (SSS), una alternativa m\xe1s econ\xf3mica a los sat\xe9lites orbitales. El grupo trabaja en la soluci\xf3n de los problemas de recuperaci\xf3n de las sondas. Las aplicaciones incluyen detecci\xf3n de cat\xe1strofes, monitoreo de biodiversidad, control clim\xe1tico, soporte al GPS y conectividad a internet en zonas sin cobertura."},{title:"Cazadores de crecidas: sistema de monitoreo de recursos h\xeddricos mediante procesamiento de im\xe1genes digitales",short_name:"Cazadores de crecidas | Monitoreo de recursos h\xeddricos",url:"https://uncinnova.unc.edu.ar/cazadores-de-crecidas-sistema-remoto-e-integral-de-monitoreo-de-recursos-hidricos-mediante-camaras-y-procesamiento-de-imagenes-digitales/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/10-TRANS-TECNO-CAZADORES.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Transformaci\xf3n tecnol\xf3gica",year:"2023",position:null,ua:["Facultad de Ciencias Exactas, F\xedsicas y Naturales"],team:["Antoine Patalano","Leandro Mass\xf3","Leticia Tarrab","Carlos Marcelo Garc\xeda"],desc:"\xabCazadores de Crecidas\xbb es un sistema de monitoreo remoto de caudales que combina c\xe1maras de vigilancia con software de velocimetr\xeda por im\xe1genes para estimar de forma continua el flujo de r\xedos y arroyos. Ya cuenta con cinco prototipos instalados en los principales cursos h\xeddricos de C\xf3rdoba. Su mayor ventaja es que opera durante crecidas extraordinarias, cuando ninguna otra metodolog\xeda resulta aplicable, siendo as\xed una herramienta \xfanica para la gesti\xf3n del riesgo h\xeddrico."},{title:"Valuaci\xf3n Masiva Automatizada (VMA) de inmuebles usando machine learning",short_name:"Valuaci\xf3n masiva automatizada de inmuebles",url:"https://uncinnova.unc.edu.ar/valuacion-masiva-automatizada-vma-de-inmuebles-usando-machine-learning/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/UNC_3890-1-1024x683-2.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Transformaci\xf3n tecnol\xf3gica",year:"2023",position:null,ua:["Facultad de Ciencias Exactas, F\xedsicas y Naturales","Centro de Estudios Territoriales (CET-UNC)","Ministerio de Finanzas del Gobierno de la Provincia de C\xf3rdoba","Infraestructura de Datos Espaciales de la Provincia de C\xf3rdoba (IDECOR)","Programa de Naciones Unidas para el Desarrollo (PNUD)",""],team:["Mario Piumetto","Hern\xe1n Morales","Juan Pablo Carranza","Mar\xeda Luz Fuentes","Aldo Algorry"],desc:"Desarrollada junto al Gobierno de la Provincia de C\xf3rdoba, la VMA aplica algoritmos de Random Forest, Redes Neuronales y Support Vector Machine para determinar las valuaciones catastrales de m\xe1s de dos millones de inmuebles urbanos y rurales cordobeses. Redujo el tiempo del proceso de tres a\xf1os a diez meses y sus resultados son accesibles en el geoportal Mapas C\xf3rdoba. El objetivo es lograr una base impositiva m\xe1s justa, actualizada y transparente para los tributos provinciales y municipales vinculados a la propiedad."},{title:"Dynamic SET: un m\xe9todo eficiente para el muestreo del flujo turbulento de agua",short_name:"Dynamic SET | Muestreo del flujo turbulento de agua",url:"https://uncinnova.unc.edu.ar/dynamic-set-un-metodo-eficiente-para-el-muestreo-del-flujo-turbulento-de-agua/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/31.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Transformaci\xf3n tecnol\xf3gica",year:"2023",position:null,ua:["Facultad de Ciencias Exactas, F\xedsicas y Naturales"],team:["Jose Manuel Diaz Lozada","Carlos Marcelo Garcia","Kevin Oberg"],desc:"Dynamic SET es un m\xe9todo que selecciona din\xe1micamente el tiempo de exposici\xf3n en cada punto de medici\xf3n de velocidad de flujo, usando la t\xe9cnica estad\xedstica Moving Block Bootstrap para estimar el Coeficiente de Variaci\xf3n de los par\xe1metros de turbulencia con el nivel de incertidumbre requerido. Ya est\xe1 siendo incorporado al firmware de los instrumentos ADCP RS5 y FlowTracker 2 de YSI/SonTek. La finalidad es optimizar las mediciones de caudal en r\xedos y arroyos reduciendo al m\xednimo el tiempo de muestreo necesario."},{title:"MediaLab de Artes – UNC",short_name:"MediaLab de Artes – UNC",url:"https://uncinnova.unc.edu.ar/medialab-de-artes-unc/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/MEDIALAB.jpg",category:"Producto, proceso o servicio innovador",topic:"Transformaci\xf3n tecnol\xf3gica",year:"2023",position:2,ua:["Facultad de Artes"],team:["Sergio Patricio Poblete Barbero","Varinnia Jofr\xe9","Laura Colombo"],desc:"El MediaLab de la Facultad de Artes re\xfane un equipo interdisciplinario de artistas, m\xfasicos, programadores y realizadores audiovisuales para ofrecer servicios tecnol\xf3gicos que no est\xe1n disponibles o son de dif\xedcil acceso en C\xf3rdoba. Entre sus prestaciones se cuentan instalaciones multimedia interactivas, realidad virtual, video 360\xb0, mapping, impresi\xf3n 3D y producci\xf3n de espect\xe1culos audiovisuales. Est\xe1 dirigido tanto a dependencias de la propia UNC como a empresas y organizaciones externas, y tambi\xe9n ofrece cursos y seminarios abiertos a la comunidad."},{title:"GEST, Instrumento Musical Virtual Gestual",short_name:"GEST | Instrumento musical virtual gestual",url:"https://uncinnova.unc.edu.ar/gest-instrumento-musical-virtual-gestual/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/GEST-Instrumento-musical-virtual-gestual-compressed-scaled-1.jpg",category:"Producto, proceso o servicio innovador",topic:"Transformaci\xf3n tecnol\xf3gica",year:"2023",position:null,ua:["Facultad de Artes"],team:["Sergio Patricio Poblete Barbero","Basilio del Boca","Varinnia Joffr\xe9","Laura Colombo","Dante Demarchi","Dylan Martin","Franco Pellini"],desc:"GEST es un instrumento musical para realidad virtual y realidad aumentada, compuesto por seis m\xf3dulos configurables —teclados, percusi\xf3n, cuerdas— que se accionan con el puntero del controlador manual del Oculus Quest 2. Permite capturar el gesto musical de forma intuitiva, sin formaci\xf3n t\xe9cnica previa. La propuesta explora nuevas interfaces de interacci\xf3n sonora y puede distribuirse y comercializarse en plataformas de aplicaciones para Realidad Virtual."},{title:"UNC 360: Plataforma de realidad virtual para el mapeo de la Ciudad Universitaria de la UNC",short_name:"Plataforma de realidad virtual para mapear Ciudad Universitaria",url:"https://uncinnova.unc.edu.ar/unc-360-mapeo-en-realidad-virtual/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/UNC-360-mapeo-en-Realidad-Virtual-scaled.jpg",category:"Producto, proceso o servicio innovador",topic:"Transformaci\xf3n tecnol\xf3gica",year:"2023",position:null,ua:["Facultad de Artes&nbsp;&nbsp;","Centro de Producci\xf3n e Investigaci\xf3n en Artes"],team:["Varinnia Jofr\xe9","Sergio Patricio Poblete","Laura Colombo","Adriana Miranda","Christian Adrian Iacono","Maria Josefina Albornoz","Martin Cesar Alaluf"],desc:"Este proyecto construye un mapeo en Realidad Virtual de toda la Ciudad Universitaria de la UNC mediante fotograf\xedas 360\xb0 de sus edificios, pabellones y facultades, accesible en l\xednea. El prop\xf3sito es que estudiantes, docentes y visitantes puedan orientarse y ubicar dependencias de forma remota y sencilla. El modelo es transferible a otros campus, parques industriales o complejos empresariales."},{title:"Digitalizaci\xf3n en alta calidad de archivos f\xedlmicos de la Universidad Nacional de C\xf3rdoba",short_name:"Digitalizaci\xf3n de archivos f\xedlmicos de la UNC",url:"https://uncinnova.unc.edu.ar/digitalizacion-uhd-de-archivos-filmicos/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/Intervencion-Telecine-CDA-12-Copy.jpg",category:"Producto, proceso o servicio innovador",topic:"Transformaci\xf3n tecnol\xf3gica",year:"2023",position:1,ua:["Facultad de Artes"],team:["Santiago Sein","Luciano Miglietta","Gustavo Alcaraz"],desc:"Este trabajo intervino el telecine del Centro de Documentaci\xf3n Audiovisual (CDA) de la UNC para elevar su resoluci\xf3n de captura a ultra alta definici\xf3n (UHD, 3840\xd72160 px), cumpliendo est\xe1ndares internacionales de preservaci\xf3n f\xedlmica. El acervo a digitalizar incluye 75.000 rollos, entre ellos el archivo hist\xf3rico del Canal 10. Al mismo tiempo, la mejora alarga la vida \xfatil del equipo existente y habilita ofrecer el servicio de digitalizaci\xf3n a terceros en el interior del pa\xeds, donde no exist\xeda alternativa al costoso mercado porte\xf1o."},{title:"Uso de la electr\xf3lisis en talleres de grabado calcogr\xe1fico sustentables para instituciones educativas",short_name:"Uso de la electr\xf3lisis en talleres de grabado calcogr\xe1fico",url:"https://uncinnova.unc.edu.ar/talleres-de-grabado-calcografico-sustentables-para-instituciones-educativas/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/10-Aguafuerte-y-aguatinta-en-Aluminio-.-Visto-con-lupa-Copy.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Transformaci\xf3n tecnol\xf3gica",year:"2023",position:null,ua:["Facultad de Artes"],team:["Santiago Sein","Luciano Miglietta","Gustavo Alcaraz"],desc:"Este proyecto ofrece formaci\xf3n, asesoramiento y materiales para implementar t\xe9cnicas electrol\xedticas de grabado calcogr\xe1fico en escuelas, facultades y talleres art\xedsticos, en reemplazo de los m\xe9todos convencionales que emplean \xe1cidos y qu\xedmicos t\xf3xicos. La electr\xf3lisis permite trabajar con aluminio y otros metales accesibles, al tiempo que reduce la contaminaci\xf3n ambiental y los riesgos laborales. La propuesta tambi\xe9n habilita la metalizaci\xf3n de objetos no conductores y la generaci\xf3n de vol\xfamenes creativos en metal."},{title:"Higia: Sistema para higiene capilar en ingravidez",short_name:"Higia | Sistema para higiene capilar en ingravidez",url:"https://uncinnova.unc.edu.ar/higia-sistema-para-higiene-capilar-en-ingravidez/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/HIGIA.png",category:"Producto, proceso o servicio innovador",topic:"Transformaci\xf3n tecnol\xf3gica",year:"2023",position:null,ua:["Facultad de Arquitectura, Urbanismo y Dise\xf1o"],team:["Candelaria Rodriguez","Victoria Ventura"],desc:"Hig\xeda es un dispositivo de higiene capilar concebido para astronautas en la Estaci\xf3n Espacial Internacional. Resuelve el lavado de cabello en condiciones de ingravidez, mediante succi\xf3n para captar el agua y absorci\xf3n para controlarla, sin contaminar el entorno. Es duradero, modular y cuenta con un cabezal de uso personal que tambi\xe9n funciona como masajeador cotidiano. Su dise\xf1o apunta a misiones de larga duraci\xf3n, como las futuras expediciones a la Luna y Marte."},{title:"Transformaci\xf3n Digital y Modernizaci\xf3n Organizacional: el proyecto para una nueva Universidad Nacional de C\xf3rdoba",short_name:"Transformaci\xf3n digital y modernizaci\xf3n organizacional",url:"https://uncinnova.unc.edu.ar/modernizacion-unc/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/11/Transformacion-Digital-y-Modernizacion-Organizacional-scaled.jpg",category:"Producto, proceso o servicio innovador",topic:"Transformaci\xf3n tecnol\xf3gica",year:"2023",position:null,ua:["Secretar\xeda de Bienestar Universitario y Modernizaci\xf3n UNC"],team:["Matias Daniel Lingua","Mar\xeda Bel\xe9n Espinoza","Maria Laura David","Dominica Rama","Juan Pablo Carranza","Lucas Boretto"],desc:"Este proyecto de la Secretar\xeda de Bienestar Universitario y Modernizaci\xf3n propone simplificar y modernizar los procesos internos de la UNC mediante metodolog\xedas \xe1giles y herramientas digitales, con estructuras m\xe1s flexibles y una cultura de innovaci\xf3n y colaboraci\xf3n. Prev\xe9 la creaci\xf3n de una Red de Modernizaci\xf3n para evaluar y priorizar proyectos de mejora continua. El prop\xf3sito es mejorar la experiencia de todos los actores de la comunidad universitaria —estudiantes, docentes y personal administrativo— y la calidad de los servicios institucionales."},{title:"InterGer: intercomprensi\xf3n en lenguas germ\xe1nicas (ILG) para hispanohablantes",short_name:"InterGer | Intercomprensi\xf3n en lenguas germ\xe1nicas",url:"https://uncinnova.unc.edu.ar/intercomprension-en-lenguas-germanicas-ilg-para-hispanohablantes-diseno-de-materiales-digitales/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/11/Intercomprension-en-lenguas-germanicas-1-scaled.jpg",category:"Producto, proceso o servicio innovador",topic:"Equidad, inclusi\xf3n y acceso al conocimiento",year:"2023",position:null,ua:["Facultad de Lenguas"],team:["Patricia Laur\xeda","Natalia Lobo","Sandra Trovarelli","Valeria Wilke"],desc:"\xabInterGer: el viaje\xbb es un curso en l\xednea, con contenidos multimediales, que ense\xf1a a leer en alem\xe1n y neerland\xe9s a hispanohablantes con nivel b\xe1sico de ingl\xe9s y sin conocimientos previos de esas lenguas. Es la primera propuesta de este tipo en Argentina y aprovecha el ingl\xe9s como puente entre las lenguas germ\xe1nicas para desarrollar la competencia lectora. Puede utilizarse como herramienta pedag\xf3gica en instituciones educativas que ofrecen cursos de idiomas."},{title:"Creaci\xf3n del Centro de Recursos para el aprendizaje y la investigaci\xf3n (CRAI) de la Facultad de Lenguas",short_name:"Recursos para aprender e investigar en Lenguas",url:"https://uncinnova.unc.edu.ar/creacion-del-centro-de-recursos-para-el-aprendizaje-y-la-investigacion-crai-de-la-facultad-de-lenguas/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/13.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Equidad, inclusi\xf3n y acceso al conocimiento",year:"2023",position:null,ua:["Facultad de Lenguas"],team:["Carolina Massimino","Mar\xeda Elisa Romano","Maria Laura Galliano","Ang\xe9liza Gaido"],desc:"El CRAI de la Facultad de Lenguas centraliza en un \xfanico espacio los recursos tecnol\xf3gicos, bases de datos, capacitaciones y asesoramiento para docentes, estudiantes e investigadores. Su rasgo distintivo frente a otras iniciativas similares es la integraci\xf3n colaborativa entre la Biblioteca, el Departamento Editorial y el Centro de Investigaciones de la propia facultad. El prop\xf3sito es potenciar la gesti\xf3n del conocimiento institucional y servir de modelo replicable para otras unidades acad\xe9micas."},{title:"Implementaci\xf3n de endodoncia mecanizada en atenci\xf3n a personas con discapacidad",short_name:"Endodoncia mecanizada para personas con discapacidad",url:"https://uncinnova.unc.edu.ar/implementacion-de-endodoncia-mecanizada-en-atencion-a-personas-con-discapacidad/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/11/Implementacion-de-endodoncia-mecanizada.png",category:"Producto, proceso o servicio innovador",topic:"Equidad, inclusi\xf3n y acceso al conocimiento",year:"2023",position:null,ua:["Facultad de Odontolog\xeda"],team:["Guadalupe Gonz\xe1lez","Horacio Martin Gonzalez","Gabriela Izurieta"],desc:"El Servicio de Atenci\xf3n Odontol\xf3gica Interdisciplinaria a Personas con Discapacidad de la Facultad de Odontolog\xeda de la UNC incorpora aparatolog\xeda de endodoncia mecanizada para tratar piezas dentales en estado cr\xedtico en pacientes que suelen llegar en situaciones avanzadas por falta de atenci\xf3n oportuna. La t\xe9cnica acorta la duraci\xf3n de las sesiones, crucial para quienes no toleran consultas prolongadas. El fin es elevar la calidad del servicio odontol\xf3gico para esta poblaci\xf3n vulnerable y mejorar su salud bucal."},{title:"Creciendo juntos en salud 2023: una estrategia para mejorar la calidad de vida en comunidades rurales",short_name:"Estrategia para mejorar la calidad de vida en comunidades rurales",url:"https://uncinnova.unc.edu.ar/creciendo-juntos-en-salud-2023-una-estrategia-para-mejorar-la-calidad-de-vida-en-comunidades-rurales/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/Creciendo-juntos-en-salud-2023-1024x1024-2.jpg",category:"Producto, proceso o servicio innovador",topic:"Equidad, inclusi\xf3n y acceso al conocimiento",year:"2023",position:null,ua:["Facultad de Odontolog\xeda","Facultad de Agronom\xeda&nbsp;","Facultad de Medicina&nbsp;","Fundaci\xf3n V\xedctor Ger\xf3nimo M\xe1rquez"],team:["Laura Patricia Gonzalez","Victor Hugo Cena Molina","Claudia Alejandra Vazquez","Marcelo Rene Marquez","Maria Alejandra Ortega"],desc:"Este proyecto de atenci\xf3n primaria de salud llega a una comunidad rural del Camino a Capilla de los Remedios, fuera de la jurisdicci\xf3n de las ciudades vecinas, articulando las facultades de Odontolog\xeda, Medicina y Agronom\xeda de la UNC. Ofrece diagn\xf3stico participativo, actividades ludo-recreativas para escolares y familias, y atenci\xf3n sanitaria en la posta de la Facultad de Agronom\xeda. La meta es mejorar la calidad de vida local promoviendo factores protectores de salud y reduciendo la brecha entre conocimiento profesional y comunidad."},{title:"La historia de la Cervecer\xeda C\xf3rdoba en Pueblo Alberdi: un informe de memoria, identidad y lucha barrial",short_name:"La historia de la Cervecer\xeda C\xf3rdoba",url:"https://uncinnova.unc.edu.ar/la-cerveceria-cordoba-en-el-pasado-presente-y-futuro-de-pueblo-alberdi-un-informe-de-memoria-identidad-y-lucha-barrial/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/WhatsApp-Image-2023-05-05-at-19.23.04-1.jpeg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Equidad, inclusi\xf3n y acceso al conocimiento",year:"2023",position:null,ua:["paulagaitan@unc.edu.ar"],team:["Facultad de Ciencias Sociales","Vecinxs Integrantes de la Red Pueblo","Centro Vecinal de Alberdi","Centro Vecinal de Villa P\xe1ez","Movimiento Trabajadores Excluidos","Secretar\xeda de Extensi\xf3n – Facultad de Ciencias Sociales – UNC","Taller de dise\xf1o cooperativo – Facultad de Arquitectura Urbanismo y Dise\xf1o – UNC","Facultad de Filosof\xeda y Humanidades (IECET- UNC- CONICET DEPTO.GEO)","Secretar\xeda de Extensi\xf3n Universitaria UNC","Ciscsa","Red Nuestra C\xf3rdoba"],desc:"Mediante una investigaci\xf3n acci\xf3n participativa con organizaciones de la Red Pueblo Alberdi, este proyecto sistematiz\xf3 las visiones de vecinos y vecinas sobre educaci\xf3n, salud, econom\xeda, g\xe9nero, h\xe1bitat e identidad barrial. Un eje central fue la demanda de recuperaci\xf3n del predio de la Cervecer\xeda C\xf3rdoba para uso comunitario. El informe resultante funcion\xf3 como herramienta de incidencia en pol\xedtica p\xfablica local e inici\xf3 el di\xe1logo con el gobierno municipal sobre las necesidades y consensos territoriales del barrio."},{title:"Transformaci\xf3n digital y gesti\xf3n \xe1gil en la administraci\xf3n p\xfablica universitaria de la FCEFyN",short_name:"Transformaci\xf3n digital y gesti\xf3n \xe1gil en la FCEFyN",url:"https://uncinnova.unc.edu.ar/transformacion-digital-y-gestion-agil-en-la-administracion-publica-universitaria-de-la-fcefyn/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/Copia-de-IMG_3021-Copy.jpg",category:"Producto, proceso o servicio innovador",topic:"Equidad, inclusi\xf3n y acceso al conocimiento",year:"2023",position:null,ua:["Facultad de Ciencias Exactas, F\xedsicas y Naturales"],team:["Camila Suaid","Juli\xe1n Gomez","Mariela Garcia"],desc:"Este proyecto incorpora metodolog\xedas \xe1giles y herramientas digitales en los procesos de gesti\xf3n administrativa de la FCEFyN para hacerlos m\xe1s eficientes y orientados a las necesidades reales de la comunidad universitaria. El dise\xf1o es iterativo: se genera contenido desde la propia gesti\xf3n y se redise\xf1a en cada ciclo seg\xfan los desaf\xedos que van surgiendo. Procura promover una cultura de innovaci\xf3n y colaboraci\xf3n en la administraci\xf3n p\xfablica universitaria."},{title:"POSTA Proyectos Open Source de Tecnolog\xedas Asistivas",short_name:"POSTA | Proyectos Open Source de Tecnolog\xedas Asistivas",url:"https://uncinnova.unc.edu.ar/posta-proyectos-open-source-de-tecnologias-asistivas/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/posta-1.png",category:"Producto, proceso o servicio innovador",topic:"Equidad, inclusi\xf3n y acceso al conocimiento",year:"2023",position:null,ua:["Facultad de Ciencias Exactas, F\xedsicas y Naturales"],team:["Diego Antonio Beltramone","Maximiliano Romero","Marcela Rivarola","Luc\xeda Garc\xeda Giacosa"],desc:"POSTA es una plataforma en l\xednea y comunidad global que nuclea a personas con discapacidad y desarrolladores de tecnolog\xedas asistivas para compartir proyectos —pr\xf3tesis, \xf3rtesis, dispositivos l\xfadicos— bajo licencias abiertas. Cada elemento posee instrucciones detalladas para su libre replicaci\xf3n y mejora colaborativa. POSTA busca democratizar el acceso a estas tecnolog\xedas al eliminar barreras econ\xf3micas y fomentar la innovaci\xf3n."},{title:"Tablero de basquet adaptado para personas con discapacidad visual",short_name:"Tablero de basquet para personas con discapacidad visual",url:"https://uncinnova.unc.edu.ar/tablero-de-basquet-adaptado-para-personas-con-discapacidad-visual/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/4-Tablero-convencional-adaptado-1.jpg",category:"Producto, proceso o servicio innovador",topic:"Equidad, inclusi\xf3n y acceso al conocimiento",year:"2023",position:null,ua:["Facultad de Ciencias Exactas, F\xedsicas y Naturales","Agencia C\xf3rdoba Deporte del Gobierno de la Provincia de C\xf3rdoba"],team:["Alejo Barrio","Pablo Balderrama","Diego Beltramone"],desc:"Este tablero de baloncesto provee retroalimentaci\xf3n auditiva instant\xe1nea tras cada lanzamiento. Emite sonidos para orientaci\xf3n espacial que permiten a personas con discapacidad visual o ceguera entrenar y jugar sin depender de asistentes videntes. Fue desarrollado con un enfoque centrado en el usuario, lo que permite configurarlo y adaptarlo a cada jugador. Promueve la autonom\xeda e inclusi\xf3n en la pr\xe1ctica deportiva y puede incorporarse en clubes, escuelas y competencias."},{title:"Nataci\xf3n inclusiva: tecnolog\xeda para nadadores con discapacidad visual",short_name:"Tecnolog\xeda para nadadores con discapacidad visual",url:"https://uncinnova.unc.edu.ar/desarrollo-de-dispositivo-para-nadadores-con-discapacidad-visual-basado-en-sensores-de-ultrasonido-e-inteligencia-artificial/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/Desarrollo-de-dispositivo-para-nadadores-con-discapacidad-visual.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Equidad, inclusi\xf3n y acceso al conocimiento",year:"2023",position:null,ua:["Facultad de Ciencias Exactas, F\xedsicas y Naturales","Fundaci\xf3n FabLab C\xf3rdoba","Fundaci\xf3n Por Igual M\xe1s","Fundaci\xf3n Gaude","Agencia C\xf3rdoba Deportes","Universidad IUAV de Venecia, Italia"],team:["Diego Antonio Beltramone","Luci Garcia Giacosa","Victor Manuel Juarez","Rocio Eliana Fernandez","Julieta Pagella","Daniel Obernauer","Marcela Fabiana Rivarola","Alejandro Daniel Cragnolini","Ana Argento Nasser","Juan Pablo Vega","Mercedes Rigo","Belen Navarrete","Diego Brazzale","Maximiliano Romero","Diego Gonzalez Dondo","Karim Kfuore"],desc:"Este dispositivo se integra al gorro de nataci\xf3n y utiliza sensores de ultrasonido e inteligencia artificial entrenada con detecci\xf3n de im\xe1genes para alertar al nadador —mediante vibraci\xf3n— cuando se aproxima al extremo de la pileta, sin necesidad de un asistente que lo golpee con una vara. Tambi\xe9n permite avisos manuales programados por el entrenador. No existe producto similar en el mercado. Gan\xf3 dos premios en el concurso INNOVAR 2022 y sus creadores proyectan aplicarlo a otras disciplinas como remo y surf."},{title:"GranMov: Desarrollo de una app de asistencia integral a peque\xf1os productores porcinos",short_name:"GranMov | App de asistencia para productores porcinos",url:"https://uncinnova.unc.edu.ar/granmov-desarrollo-de-una-app-de-asistencia-integral-a-pequenos-productores-porcinos-de-la-provincia-de-cordoba/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/eco2-min.jpg",category:"Producto, proceso o servicio innovador",topic:"Equidad, inclusi\xf3n y acceso al conocimiento",year:"2023",position:null,ua:["Facultad de Ciencias Econ\xf3micas","C\xe1mara de Productores Porcinos de la provincia de C\xf3rdoba"],team:["In\xe9s del Valle Asis","Silvia Elena Aisa","Alejandro Edgardo Torres","Daniel Antonio Parisi","Luciano Ferreira"],desc:"GranMov es una aplicaci\xf3n m\xf3vil que releva datos productivos y de geolocalizaci\xf3n de peque\xf1os productores porcinos de C\xf3rdoba, hoy dispersos y sin informaci\xf3n sistematizada. Su fin es reducir la brecha tecnol\xf3gica del sector, identificar necesidades de asistencia t\xe9cnica y generar estad\xedsticas confiables para la toma de decisiones del sector p\xfablico. La plataforma funciona con y sin conexi\xf3n a internet, y fue desarrollada en articulaci\xf3n con la C\xe1mara de Productores Porcinos de la provincia."},{title:"M\xe1s all\xe1 de los ingresos: hacia una medici\xf3n multidimensional de la pobreza en Argentina",short_name:"Medici\xf3n multidimensional de la pobreza en Argentina",url:"https://uncinnova.unc.edu.ar/mas-alla-de-los-ingresos-hacia-una-medicion-multidimensional-de-la-pobreza-en-argentina/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/FCE_1421.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Equidad, inclusi\xf3n y acceso al conocimiento",year:"2023",position:null,ua:["Facultad de Ciencias Econ\xf3micas"],team:["Adri\xe1n M. Moneta Pizarro","Mar\xeda Alejandra Ju\xe1rez","Jos\xe9 Luis Arrufat","Mar\xeda del Huerto Allub","Leiza Camilo Caro","Mariana Laspina","Bruno Fagnola","Ana Paula Satorres Bechara","Jos\xe9 Agust\xedn Cugno","Denise Guti\xe9rrez Montecino."],desc:"Este proyecto aplica modelos de ecuaciones estructurales (SEM y GSEM) a los datos de la Encuesta Permanente de Hogares del INDEC para medir la pobreza multidimensional en Argentina. Identifica privaciones en m\xfaltiples dimensiones, m\xe1s all\xe1 del ingreso monetario. Los pesos asignados a cada dimensi\xf3n se determinan de forma emp\xedrica, sin supuestos normativos previos. La metodolog\xeda no tiene antecedentes en el pa\xeds y busca orientar con mayor precisi\xf3n las pol\xedticas p\xfablicas de reducci\xf3n de la pobreza."},{title:"\xa8Mi Vestir\xa8: Vestimenta adaptada para personas con movilidad reducida en los miembros superiores",short_name:"Vestimenta para personas con movilidad reducida",url:"https://uncinnova.unc.edu.ar/%c2%a8mi-vestir%c2%a8-vestimenta-adaptada-para-personas-con-linfedema-para-uso-en-el-hogar-durante-la-terapia-descongestiva-compleja-o-personas-con-movilidad-reducida-en-los-miembros-superiores/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/mi-vestir-scaled.jpg",category:"Producto, proceso o servicio innovador",topic:"Equidad, inclusi\xf3n y acceso al conocimiento",year:"2023",position:null,ua:["Facultad de Arquitectura, Urbanismo y Dise\xf1o"],team:["Alvarez Vallero In\xe9s","Bonino Ornella Azul","Legato Milagros"],desc:"\xabMi Vestir\xbb es una prenda informal de dos piezas, con cierres imantados y apertura lateral. Fue dise\xf1ada para que personas con linfedema o movilidad reducida en los miembros superiores puedan vestirse de forma aut\xf3noma, sin esfuerzo y en poco tiempo. Es reversible para ambos brazos y la prenda se adapta al tama\xf1o variable del linfedema. Fue creada para ampliar la independencia cotidiana de estos pacientes durante y fuera de la terapia descongestiva compleja."},{title:"Biomodelos: tecnolog\xeda para mejorar la precisi\xf3n y eficiencia en la medicina de intervenci\xf3n",short_name:"Biomodelos para mejorar la precisi\xf3n en la medicina",url:"https://uncinnova.unc.edu.ar/biomodelos-tecnologia-para-mejorar-la-precision-y-eficiencia-en-la-medicina-de-intervencion/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/Cerebro-MRI.jpg",category:"Producto, proceso o servicio innovador",topic:"Salud humana",year:"2023",position:null,ua:["Facultad de Arquitectura, Urbanismo y Dise\xf1o"],team:["Victor Defago","Gabriel Massano","Anabel Ilardo","Ignacio Sipowicz","Santiago Fernandez","Silvio Chaile"],desc:"Los biomodelos son r\xe9plicas f\xedsicas o virtuales de la anatom\xeda de pacientes, obtenidas por impresi\xf3n 3D a partir de im\xe1genes m\xe9dicas. Permiten planificar cirug\xedas con antelaci\xf3n, dise\xf1ar gu\xedas de corte y moldes para placas met\xe1licas o pr\xf3tesis a medida. No solo reduce los tiempos quir\xfargicos, sino que mejorar la interpretaci\xf3n espacial de los m\xe9dicos. Adem\xe1s, puede utilizarse como material did\xe1ctico y de simulaci\xf3n en la formaci\xf3n m\xe9dica."},{title:"Biomateriales odontol\xf3gicos y tejido biol\xf3gico magn\xe9tico generado por t\xe9cnicas de ingenier\xeda tisular",short_name:"Biomateriales generados por t\xe9cnicas de ingenier\xeda tisular",url:"https://uncinnova.unc.edu.ar/control-de-calidad-de-biomateriales-odontologicos-y-de-un-tejido-biologico-magnetico-generado-por-tecnicas-de-ingenieria-tisular/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/index.jpeg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Salud humana",year:"2023",position:null,ua:["Facultad de Odontolog\xeda","Universidad de Granada en Espa\xf1a","Sector empresarial de Argentina"],team:["Karina Grunberg","Mario Anibal Rodriguez","Maria Belen Ferrer","Lucas Sorbera","Rosario Martinez","Guadalupe Dorado","Victor Carriel","Fernando Campos","Modesto T Lopez-Lopez"],desc:"Este proyecto desarroll\xf3 un tejido artificial magn\xe9tico a partir de una matriz de fibrina y agarosa con nanopart\xedculas magn\xe9ticas incorporadas. El objetivo es guiar la regeneraci\xf3n de tejidos mineralizados, como hueso y dentina, mediante campos magn\xe9ticos externos. La patente fue aprobada por la agencia espa\xf1ola, la Comunidad Europea y registrada en Estados Unidos. La combinaci\xf3n de tejidos artificiales magn\xe9ticos y campos magn\xe9ticos para potenciar la regeneraci\xf3n \xf3sea es una alternativa poco explorada a nivel mundial."},{title:"Desarrollo de un sellador quir\xfargico a base de prote\xednas humanas para promover la cicatrizaci\xf3n de heridas",short_name:"Sellador quir\xfargico a base de prote\xednas humanas",url:"https://uncinnova.unc.edu.ar/desarrollo-de-un-sellador-quirurgico-a-base-de-proteinas-humanas-para-promover-la-cicatrizacion-de-heridas/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/la-trombina-convierte-el-fibrinogeno-en-fibrina-lo-que-hace-polimerice-y-genere-coagulos-de-sangre-moleculas-rojas-activan-183970741.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Salud humana",year:"2023",position:null,ua:["Laboratorio de Hemoderivados UNC"],team:["Federico Far\xedas","Ricardo Lombardi","Romina Rodr\xedguez","Hugo Guglielmone","Gonzalo Rodr\xedguez","Mar\xeda Eugenia Bernardi"],desc:"Este proyecto desarrolla los componentes —trombina y fibrin\xf3geno— del medicamento \xabsellante de fibrina\xbb a partir de plasma humano, usualmente aplicado como sellador quir\xfargico y promotor de cicatrizaci\xf3n en distintos tipos de cirug\xedas. Actualmente no existe producci\xf3n nacional de este producto. Al ser biocompatible y biodegradable, no induce inflamaci\xf3n excesiva ni reacciones inmunol\xf3gicas, y tambi\xe9n tiene potencial en ingenier\xeda de tejidos y consolidaci\xf3n de fracturas."},{title:"Dise\xf1o y desarrollo de aloinjertos \xf3seos antibacterianos",short_name:"Aloinjertos \xf3seos antibacterianos",url:"https://uncinnova.unc.edu.ar/diseno-y-desarrollo-de-aloinjertos-oseos-antibacterianos/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/foto-hueso-con-lupa.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Salud humana",year:"2023",position:null,ua:["Facultad de Ciencias Qu\xedmicas","Laboratorio de Nanotecnolog\xeda y Biomateriales UNC&nbsp;","Instituto de Investigaciones en Ciencias de la Salud UNC","Laboratorio de Hemoderivados"],team:["Daniela Quinteros","Cecilia Tettamanti","Cecilia Sobrero","Daniel Allemandi"],desc:"Este proyecto dise\xf1a aloinjertos de polvo \xf3seo de piezas dentales, impregnados con nanopart\xedculas de Alb\xfamina S\xe9rica Humana (ASH) cargadas con vancomicina, para liberar el antibi\xf3tico de forma local, lenta y controlada en cirug\xedas de injerto. El fin es reducir la terapia antibi\xf3tica sist\xe9mica en cirug\xeda odontol\xf3gica, minimizar los efectos adversos y el desarrollo de resistencia bacteriana. No existe actualmente en el mercado un producto similar basado en nanotecnolog\xeda."},{title:"Dispositivos pedag\xf3gicos para la promoci\xf3n de entornos escolares saludables",short_name:"Promoci\xf3n de entornos escolares saludables",url:"https://uncinnova.unc.edu.ar/dispositivos-pedagogicos-para-la-participacion-de-ninos-ninas-y-adolescentes-en-la-creacion-de-entornos-escolares-saludables/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/Dispositivos-pedagogicos-scaled.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Salud humana",year:"2023",position:null,ua:["Escuela de Nutrici\xf3n","Facultad de Ciencias M\xe9dicas","Centro de Investigaci\xf3n Epidemiol\xf3gica y en Servicios de Salud (CIESS)","Centro de Investigaciones y Estudios sobre Cultura y Sociedad (CIECS)","Consejo Nacional de Investigaciones Cient\xedficas y T\xe9cnicas (CONICET)","Ministerio de Educaci\xf3n de la Provincia de C\xf3rdoba","Ministerio de Salud de la Provincia de C\xf3rdoba","",""],team:["Silvina Berra","Ver\xf3nica Mamondi","Mar\xeda Dolores Rom\xe1n","Ana Moos","Tamara Silva","Romina Soledad Biondini","Virginia Miranda","Francisco Martin Fantini","Luisina Rivadero","Jeanette Peralta"],desc:"Consiste en el desarroll\xf3 de un cuaderno de trabajo para docentes de nivel medio con estrategias para promover h\xe1bitos alimentarios saludables y prevenir el sobrepeso y la obesidad en el \xe1mbito escolar, en articulaci\xf3n con los ministerios de Educaci\xf3n y Salud de C\xf3rdoba. Se implement\xf3 mediante talleres con docentes y estudiantes, usando Instagram como canal comunicacional. Su prop\xf3sito es que los alumnos sean sujetos activos de su propio cuidado, y que el material sea replicable en otras instituciones educativas."},{title:"Polimorfismos gen\xe9ticos del hu\xe9sped asociados a la miocardiopat\xeda chag\xe1sica cr\xf3nica",short_name:"Chagas | Polimorfismos gen\xe9ticos del hu\xe9sped",url:"https://uncinnova.unc.edu.ar/polimorfismos-geneticos-del-huesped-asociados-a-la-miocardiopatia-chagasica-cronica/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/PCR_1.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Salud humana",year:"2023",position:null,ua:["Facultad de Ciencias M\xe9dicas","Comisi\xf3n Nacional de Investigaciones Cient\xedficas y T\xe9cnicas (CONICET)"],team:["Silvina Lo Presti","Alejandra Lidia B\xe1ez","Patricia Paglini","Gustavo Guzm\xe1n Mentesana","Sergio Lucino","Noem\xed del Carmen Miler","Mercedes Rosa Ferrero","Hugo Fern\xe1ndez","Franco Mersch\xf3n","Romina Blasco","Daniela Alejandra Vel\xe1zquez-L\xf3pez"],desc:"Este proyecto estudia variantes gen\xe9ticas en genes de respuesta inmune y funci\xf3n card\xedaca de pacientes cordobeses infectados por Trypanosoma cruzi. La finalidad es establecer un perfil gen\xe9tico de riesgo que permita predecir qu\xe9 personas evolucionar\xe1n hacia la miocardiopat\xeda chag\xe1sica cr\xf3nica. Identificarlas en etapas tempranas permitir\xeda un seguimiento diferencial y un tratamiento m\xe1s adecuado para los afectados, que representan el 30% de los infectados."},{title:"Detecci\xf3n de virus en alimentos aplicando metodolog\xedas moleculares",short_name:"Detecci\xf3n de virus en alimentos",url:"https://uncinnova.unc.edu.ar/desarrollo-implementacion-y-transferencia-de-metodologia-molecular-para-la-deteccion-de-virus-en-alimentos/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/190917-Aca7-des-f1-detectar-patogenos-alimentos.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Salud humana",year:"2023",position:null,ua:["Facultad de Ciencias M\xe9dicas","LACE Laboratorios"],team:["Viviana R\xe9","Mar\xeda Bel\xe9n Pisano","Silvia Nates","Gisela Masachessi","Ver\xf3nica Prez","Laura Martinez","Guadalupe Di Cola","Osvaldo Elbarcha","Maribel Martinez Wassaf","Evelyn Butassi","Fernando Luis Arriba"],desc:"Se trat de la implemntaci\xf3n y transferencia de t\xe9cnicas moleculares —extracci\xf3n de ARN, amplificaci\xf3n de \xe1cidos nucleicos viral individual y m\xfaltiple con control interno— para detectar virus pat\xf3genos en distintas matrices alimenticias. Busca ofrecer al sector productivo y a los organismos de control una herramienta que garantice la inocuidad de los alimentos, as\xed como cumplir con las exigencias de importaci\xf3n de mercados europeos, que requieren certificaci\xf3n libre de Norovirus y Hepatitis A en frutos del bosque."},{title:"Vigilancia ambiental de virus de transmisi\xf3n ent\xe9rica: una herramienta para las pol\xedticas p\xfablica",short_name:"Vigilancia ambiental de virus de transmisi\xf3n ent\xe9rica",url:"https://uncinnova.unc.edu.ar/vigilancia-ambiental-de-virus-de-transmision-enterica-como-herramienta-complementaria-a-la-vigilancia-clinica-transferencia-para-su-uso-en-politicas-publicas/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/2023-05-12-Instituto-Virlogico-Ph-Atrezzo-Productora-203-1.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Salud humana",year:"2023",position:null,ua:["Instituto de Virolog\xeda / Facultad de Ciencias M\xe9dicas","Secretar\xeda de Prevenci\xf3n y Promoci\xf3n de la Salud, Laboratorio Central y Direcci\xf3n de Epidemiolog\xeda / Ministerio de Salud de la Provincia de C\xf3rdoba / Comisi\xf3n Nacional de Investigaciones Cient\xedficas y T\xe9cnicas (CONICET)",""],team:["Viviana R\xe9","Mar\xeda Bel\xe9n Pisano","Silvia Nates","Gisela Masachessi","Ver\xf3nica Prez","Anabella Fantilli","Guadalupe Di Cola","Mar\xeda de los \xc1ngeles Marinzalda","Ariana Mariela Cachi","Pilar Adamo","Mar\xeda Bel\xe9n Colazo Salbetti","Mar\xeda Gabriela Barbas","Laura Lopez","Gonzalo Castro","Paola Sicilia"],desc:"Esta iniciativa aplica la detecci\xf3n molecular de virus ent\xe9ricos y sus variantes en muestras ambientales para monitorear la circulaci\xf3n viral en poblaciones urbanas, incluso donde hay escasa notificaci\xf3n cl\xednica de casos. Los datos se transfieren al Ministerio de Salud de C\xf3rdoba para activar medidas preventivas anticipadas. La finalidad es incorporar la vigilancia ambiental como una pol\xedtica p\xfablica sistem\xe1tica que complemente la vigilancia cl\xednico-epidemiol\xf3gica convencional."},{title:"Incorporaci\xf3n de tecnolog\xeda digital en la planificaci\xf3n de rehabilitaciones dentarias",short_name:"Tecnolog\xeda digital en las rehabilitaciones dentarias",url:"https://uncinnova.unc.edu.ar/incorporacion-de-tecnologia-digital-en-la-planificacion-de-rehabilitaciones-dentarias/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/11/Incorporacion-de-tecnologia-digital-scaled.jpg",category:"Producto, proceso o servicio innovador",topic:"Salud humana",year:"2023",position:null,ua:["Facultad de Odontolog\xeda"],team:["Guillermo Peralta","Adriana Piacenza","Paula Tarasco","Sol Mar\xeda Bern\xe1rdez","Roc\xedo D\xedaz Spalletti","Jerem\xedas Cento","Sebasti\xe1n Pablo Paesani Lagger"],desc:"Incorpora esc\xe1neres intraorales, software de dise\xf1o y tecnolog\xeda digital a los procesos de diagn\xf3stico y planificaci\xf3n de rehabilitaciones dentales en la Facultad de Odontolog\xeda de la UNC. De esa manera se apunta a lograr tratamientos m\xe1s precisos, predecibles y eficientes, reducir las sesiones y tiempos de trabajo, as\xed como ampliar la oferta asistencial en una instituci\xf3n p\xfablica. Tambi\xe9n tiene un componente pedag\xf3gico para la formaci\xf3n de estudiantes de grado y posgrado."},{title:"Hueso humano potenciado con factores de crecimiento de la sangre",short_name:"Hueso humano potenciado con factores de crecimiento de la sangre",url:"https://uncinnova.unc.edu.ar/hueso-humano-de-banco-del-laboratorio-de-hemoderivados-de-la-unc-potenciado-con-factores-de-crecimiento-de-la-sangre/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/Hueso-humano-de-Banco-del-Laboratorio-de-Hemoderivados-274x300-1.jpg",category:"Producto, proceso o servicio innovador",topic:"Salud humana",year:"2023",position:null,ua:["Facultad de Odontolog\xeda&nbsp;","Laboratorio de Hemoderivados UNC"],team:["Osvaldo Calabrese","Luis Rodrigo Belotti","Carolina Lacerra","Cecilia Sobrero"],desc:"Esta t\xe9cnica combina hueso humano del Banco del Laboratorio de Hemoderivados de la UNC con Fibrina Rica en Plaquetas (PRF), obtenida de la propia sangre del paciente. Esto logra una concentraci\xf3n del 100% de prote\xednas morfogen\xe9ticas, que aceleran la regeneraci\xf3n \xf3sea y de tejidos blandos en la cavidad oral. La obtenci\xf3n del material es poco invasiva, minimiza el riesgo de rechazo y permite activar implantes en menor tiempo, con menor dolor y edema postquir\xfargico."},{title:"Exposici\xf3n a fluoruros y fluorosis dental: “Construyendo juntos para que el agua no manche”",short_name:"Exposici\xf3n a fluoruros y fluorosis dental",url:"https://uncinnova.unc.edu.ar/exposicion-a-fluoruros-y-fluorosis-dental-construyendo-juntos-para-que-el-agua-no-manche/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/11/Exposicion-a-fluoruros-y-fluorosis-dental.png",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Salud humana",year:"2023",position:null,ua:["Facultad de Odontolog\xeda&nbsp;","Comisi\xf3n Nacional de Investigaciones Cient\xedficas y T\xe9cnicas (CONICET)",""],team:["Gallar\xe1 Raquel Vivian","Piazza Leonardo Alberto","Bojanich Mar\xeda Alejandra","Centeno Viviana Andrea","Delgado Mar\xeda Andrea","Rozas Carlos Alfredo","Rodr\xedguez Ismael Angel","Ponce Rub\xe9n Hugo"],desc:"Este estudio est\xe1 abocado a determinar la prevalencia de fluorosis dental en ni\xf1os y ni\xf1as en edad escolar que habitan zonas de C\xf3rdoba con alta concentraci\xf3n de fluoruro en el agua de bebida, adem\xe1s de evaluar fuentes de agua segura en esos territorios. Como soluci\xf3n, desarrolla un sistema domiciliario de manufactura casera para remover el fluoruro, de bajo costo, f\xe1cil instalaci\xf3n y mantenimiento simple. Adem\xe1s, implementa actividades de promoci\xf3n de salud general y bucodental en las comunidades afectadas."},{title:"Protocolo de atenci\xf3n de la salud a mujeres rurales del norte de C\xf3rdoba",short_name:"Protocolo de atenci\xf3n de la salud a mujeres rurales",url:"https://uncinnova.unc.edu.ar/protocolo-de-atencion-de-la-salud-a-mujeres-rurales-del-norte-de-cordoba/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/11/Protocolo-de-atencion-de-la-salud-a-mujeres-rurales.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Salud humana",year:"2023",position:null,ua:["Facultad de Ciencias Sociales","Escuela de Nutrici\xf3n"],team:["Nayla Luz Prado","Eliana L\xf3pez","Jos\xe9 M\xe1ntaras"],desc:"Este proyecto sistematiza conocimientos y pr\xe1cticas de los colectivos de mujeres del norte de C\xf3rdoba en torno a la Salud Sexual, Reproductiva y No Reproductiva, y los organiza en un protocolo. Este instrumento consta de dos partes: una secci\xf3n informativa con aprendizajes clave de las consejer\xedas y una caja de herramientas para instalar capacidades comunitarias. Se procura mejorar el acceso a la salud desde una perspectiva de g\xe9nero, fortaleciendo los propios recursos de las comunidades rurales alejadas del sistema de salud formal."},{title:"Regenecip: membranas regenerativas para el tratamiento de heridas infectadas",short_name:"Regenecip | Membranas regenerativas para heridas infectadas",url:"https://uncinnova.unc.edu.ar/investigacion-y-desarrollo-de-membranas-biopolimericas-regenerativas-para-el-tratamiento-de-heridas-infectadas/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/09/2023-05-31-UNC-Innova-03-interiores-7.jpg",category:"Producto, proceso o servicio innovador",topic:"Salud humana",year:"2023",position:null,ua:["Facultad de Ciencias Qu\xedmicas","Comisi\xf3n Nacional de Investigaciones Cient\xedficas y T\xe9cnicas (CONICET)"],team:["Mar\xeda Eugenia Olivera","Mar\xeda Florencia S\xe1nchez","Mar\xeda Laura Guzm\xe1n","Carolina Luciani","Karem Arrigoni","Fiama Bolatti","Fiamma Barbieri"],desc:"Regenecip es una membrana bioadhesiva antibi\xf3tico-anest\xe9sica (MBAA) fabricada con pol\xedmeros biocompatibles. Se aplica directamente sobre la piel para tratar infecciones cr\xf3nicas como quemaduras, \xfalceras y heridas postoperatorias. Libera el f\xe1rmaco de forma sostenida, reduce la resistencia bacteriana, evita el uso sist\xe9mico de antibi\xf3ticos y su administraci\xf3n es sencilla y no invasiva. Su potencial tambi\xe9n se extiende a la prevenci\xf3n de futuras infecciones."},{title:"Membranas de col\xe1geno modificadas para regeneraci\xf3n tisular guiada",short_name:"Membranas de col\xe1geno para la regeneraci\xf3n tisular guiada",url:"https://uncinnova.unc.edu.ar/membranas-de-colageno-modificadas-para-regeneracion-tisular-guiada/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/5-SALUD-HUMANA-portada.jpg",category:"Producto, proceso o servicio innovador",topic:"Salud humana",year:"2023",position:null,ua:["Facultad de Ciencias Qu\xedmicas","Laboratorio Inbiomed"],team:["Nahuel Matias Camacho","Santiago Daniel Palma","Agustin Gonzalez","Cecilia Alvarez Igarzabal","Mariano Murature"],desc:"Este proyecto optimiza una membrana reabsorbible de col\xe1geno entrecruzada con genipina. Esto aumenta su permanencia en el sitio de implante para que no se reabsorba antes de que el tejido se regenere por completo, especialmente en procesos lentos como el \xf3seo. Al evitar un segundo procedimiento quir\xfargico de retiro, se reduce el riesgo de infecci\xf3n y de nuevos defectos. La membrana es apir\xf3gena, est\xe9ril, biocompatible y mantiene sus propiedades mec\xe1nicas y f\xedsico-qu\xedmicas originales."},{title:"Formulaciones s\xf3lidas dispersables para el tratamiento pedi\xe1trico de la tuberculosis",short_name:"Formulaciones para el tratamiento pedi\xe1trico de la tuberculosis",url:"https://uncinnova.unc.edu.ar/formulaciones-solidas-dispersables-de-sabor-aceptable-para-el-tratamiento-pediatrico-de-la-tuberculosis/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/Comprimidos-CMC-RIF-foto2.jpg",category:"Producto, proceso o servicio innovador",topic:"Salud humana",year:"2023",position:null,ua:["Facultad de Ciencias Qu\xedmicas","Consejo Nacional de Investigaciones Cient\xedficas y T\xe9cnicas (CONICET)"],team:["Laura Carolina Luciani Giacobbe","Mar\xeda Eugenia Olivera","Fiama Georgina Bolatti"],desc:"Consiste en el desarrollo de comprimidos dispersables de la triple combinaci\xf3n antituberculosa (rifampicina, isoniazida, pirazinamida) con sabor agradable y de r\xe1pida disoluci\xf3n en peque\xf1os vol\xfamenes de agua, adaptados a las necesidades de dosificaci\xf3n pedi\xe1trica. El producto, de fabricaci\xf3n local, apunta a sustituir importaciones y tiene potencial de exportaci\xf3n regional. Se trabajar\xe1 en colaboraci\xf3n con laboratorios p\xfablicos de producci\xf3n de medicamentos."},{title:"QQ1cream: equipo para la preparaci\xf3n autom\xe1tica de semis\xf3lidos",short_name:"QQ1cream | Preparaci\xf3n autom\xe1tica de semis\xf3lidos",url:"https://uncinnova.unc.edu.ar/qq1cream-equipo-para-la-preparacion-automatica-de-semisolidos/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/2.png",category:"Producto, proceso o servicio innovador",topic:"Salud humana",year:"2023",position:null,ua:["Facultad de Ciencias Qu\xedmicas","Consejo Nacional de Investigaciones Cient\xedficas y T\xe9cnicas (CONICET)"],team:["Juan Pablo Real","Daniel Real","Emiliano Frenquelli","Santiago Palma"],desc:"QQ1cream es un equipo de producci\xf3n semiautomatizada de semis\xf3lidos farmac\xe9uticos —cremas, geles, pomadas y pastas— que integra en un solo dispositivo la mezcla, calentamiento y envasado, con funci\xf3n de autolavado. Reemplaza planchas de agitaci\xf3n, morteros y esp\xe1tulas, al tiempo que reduce pasos y tiempos de elaboraci\xf3n. No existe en el mercado regional un equipo equivalente. Est\xe1 pensado para farmacias y laboratorios de baja escala que buscan automatizar la producci\xf3n de preparados magistrales."},{title:"Harina de hojas de remolacha: revalorizaci\xf3n y uso para la elaboraci\xf3n de un alimento con potencial antioxidante y rica en hierro",short_name:"Harina de hojas de remolacha para preparar alimentos",url:"https://uncinnova.unc.edu.ar/hojas-de-remolacha-revalorizacion-y-uso-para-la-elaboracion-de-un-alimento-con-potencial-antioxidante-y-rica-en-hierro/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/2-remolacha.jpg",category:"Producto, proceso o servicio innovador",topic:"Salud humana",year:"2023",position:null,ua:["Facultad de Ciencias M\xe9dicas","Conicet"],team:["Claudia Albrecht","Natalia Cervilla","Nehuen Codina","Natal\xed Luz Mar\xeda Sueldo","Tamara Valdez"],desc:"Este proyecto deshidrata las hojas de remolacha —habitualmente descartadas como subproducto agr\xedcola— para obtener una harina de alta capacidad antioxidante y rico contenido de hierro, de bajo costo y con reducido impacto ambiental. Puede incorporarse en batidos, jugos, preparaciones culinarias o mate. Busca revalorizar este residuo vegetal como ingrediente funcional, contribuye a fortalecer el aporte nutricional de la alimentaci\xf3n y a una producci\xf3n de alimentos m\xe1s sostenible."},{title:"Obtenci\xf3n de andamios 3D de col\xe1geno y \xe1cido hialur\xf3nico para regeneraci\xf3n cut\xe1nea",short_name:"Andamios 3D de col\xe1geno y \xe1cido hialur\xf3nico para regeneraci\xf3n cut\xe1nea",url:"https://uncinnova.unc.edu.ar/obtencion-y-caracterizacion-de-andamios-impresos-en-3d-de-colageno-y-acido-hialuronico-para-su-uso-en-ingenieria-en-tejidos-2/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/Andamios-impresos-3d-de-colageno-y-acido-hialuronico.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Salud humana",year:"2023",position:1,ua:["Facultad de Ciencias Exactas, F\xedsicas y Naturales","Consejo Nacional de Investigaciones Cient\xedficas y T\xe9cnicas (CONICET)"],team:["Pablo Andr\xe9s Fern\xe1ndez","Romina Com\xedn","Nancy Salvatierra","Mariana Cid"],desc:"Este proyecto extrae col\xe1geno tipo I de piel porcina mediante un m\xe9todo sencillo y econ\xf3mico que preserva las fibras sin desnaturalizarlas, lo combina con \xe1cido hialur\xf3nico comercial y formula una tinta imprimible en 3D. Las estructuras obtenidas se liofilizan para mantener su porosidad y se estabilizan con entrecruzamiento qu\xedmico. Su uso potencial es la regeneraci\xf3n de tejidos cut\xe1neos lesionados o faltantes en el campo de la ingenier\xeda de tejidos."},{title:"Muuuta: Sistema de construcci\xf3n de tambos modulares",short_name:"Muuuta | Sistema de construcci\xf3n de tambos modulares",url:"https://uncinnova.unc.edu.ar/sistema-de-construccion-de-tambos-modulares/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/02_MUUUTA-1.jpg",category:"Producto, proceso o servicio innovador",topic:"Bioeconom\xeda",year:"2023",position:null,ua:["Facultad de Arquitectura, Urbanismo y Dise\xf1o"],team:["Mait\xe9 Daniela Oddi","Juan Cruz Martinez","Gerardo Mayer"],desc:"Muuuta es un sistema constructivo de tambo desmontable y modular dise\xf1ado para peque\xf1os productores lecheros de la cuenca central argentina. A diferencia de las construcciones convencionales, permite recuperar el 95% de la inversi\xf3n inicial ya que puede trasladarse, reutilizarse y revenderse. Es resistente a la intemperie, compatible con instalaciones de paneles solares y pensado para una producci\xf3n sustentable y eficiente en el uso de recursos."},{title:"Utilizaci\xf3n de frutos aut\xf3ctonos seleccionados para elaboraci\xf3n de cerveza artesanal",short_name:"Uso de frutos aut\xf3ctonos para elaborar cerveza artesanal",url:"https://uncinnova.unc.edu.ar/utilizacion-de-frutos-autoctonos-seleccionados-para-elaboracion-de-cerveza-artesanal/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/botellas.jpg",category:"Producto, proceso o servicio innovador",topic:"Bioeconom\xeda",year:"2023",position:null,ua:["Facultad de Ciencias Exactas, F\xedsicas y Naturales"],team:["Pedro Alvargonzalez"],desc:"Este proyecto analiza los frutos de cha\xf1ar y mistol, nativos del centro y NOA de Argentina, y ensaya distintos m\xe9todos de adici\xf3n y combinaci\xf3n para producir cervezas artesanales con perfiles organol\xe9pticos diferenciados. El prop\xf3sito es generar valor agregado a partir de frutos que hoy tienen escasa utilizaci\xf3n comercial y potenciar, con esa estrategia, las econom\xedas regionales al abrir un nicho en la industria cervecera artesanal."},{title:"De residuos a recursos: oportunidades de bioeconom\xeda circular en cadenas de valor agroindustriales",short_name:"De residuos a recursos: oportunidades de bioeconom\xeda circular",url:"https://uncinnova.unc.edu.ar/de-residuos-a-recursos-relevamiento-sobre-las-posibilidades-de-un-modelo-de-bioeconomia-circular-en-cadenas-de-valor-agroindustriales-argentinas/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/2-BIOECONOMIA.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Bioeconom\xeda",year:"2023",position:null,ua:["Facultad de Ciencias Econ\xf3micas","Universidad Nacional de Salta","Universidad Nacional de La Rioja","Instituto Nacional de Tecnolog\xeda Industrial","Ministerio de Ciencia, Tecnolog\xeda e Innovaci\xf3n de la Naci\xf3n Argentina"],team:["Celina Amato","M\xf3nica Buraschi","Mar\xeda Florencia Peretti","Sofia Gonz\xe1lez"],desc:"Bajo un modelo de bioeconom\xeda circular, esta iniciativa releva oportunidades de aprovechamiento de subproductos en siete cadenas agroindustriales argentinas: bioetanol de ma\xedz, jojoba, alimentos nutrac\xe9uticos, carne bovina, carne aviar, industria forestal e industria vitivin\xedcola. El prop\xf3sito es identificar c\xf3mo convertir esos residuos en recursos, minimizar la contaminaci\xf3n y regenerar los sistemas naturales, lo que permite generar insumos para el dise\xf1o de pol\xedticas p\xfablicas de desarrollo sostenible."},{title:"Modelo de gesti\xf3n para la simbiosis industrial en el sector bioetanol",short_name:"Modelo de gesti\xf3n para la simbiosis industrial en el sector bioetanol",url:"https://uncinnova.unc.edu.ar/modelo-de-gestion-para-la-simbiosis-industrial-estudio-de-caso-a-partir-del-sector-de-bioetanol-de-cordoba-argentina/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2023/05/1-BIOECONOMIA-1.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Bioeconom\xeda",year:"2023",position:2,ua:["Facultad de Ciencias Econ\xf3micas"],team:["Sof\xeda Gonzalez"],desc:"Este proyecto dise\xf1a un modelo de gesti\xf3n para articular redes de simbiosis industrial en el sector de bioetanol de ma\xedz de C\xf3rdoba y San Luis, conectando a productores de biomasa residual con empresas que los utilizan como materia prima. Estudia tres casos concretos en Villa Mar\xeda, Yanquetruz y R\xedo Cuarto/Alejandro Roca. El fin es maximizar el aprovechamiento de subproductos, generar beneficios econ\xf3micos, sociales y ambientales, as\xed como aportar conocimiento transferible a otros sectores productivos."}],database_2024=[{title:"Andamios vegetales a base de hojas de espinaca para ingenier\xeda de tejidos",short_name:"Hojas de espinaca para ingenier\xeda de tejidos",url:"https://uncinnova.unc.edu.ar/andamios-vegetales-a-base-de-hojas-de-espinaca-para-ingenieria-de-tejidos/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/06/5.8-PORTADA-1024x512.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Salud humana",ua:["Facultad de Ciencias Exactas, F\xedsicas y Naturales"],year:"2024",position:null,team:["Ludmila Aiassa","Tom\xe1s Rearte","Mariana Cid","Romina Com\xedn","Nancy Salvatierra"],desc:"Este proyecto produce andamios tridimensionales de origen vegetal a partir de hojas de espinaca descelularizadas. Ofrecen propiedades bioqu\xedmicas y mec\xe1nicas \xf3ptimas para sostener el crecimiento celular. Son una alternativa sostenible y econ\xf3mica a los andamios de origen animal, con potencial de uso en diversas aplicaciones cl\xednicas."},{title:"PRO.TEC | Barrera modular para mejorar el autoconsumo en ganader\xeda y reducir el desperdicio de alimento",short_name:"Barrera para mejorar el autoconsumo en ganader\xeda",url:"https://uncinnova.unc.edu.ar/pro-tec-barrera-modular-para-mejorar-el-autoconsumo-en-ganaderia-y-reducir-el-desperdicio-de-alimento/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/06/renderizado-de-los-tres-silos-Protec-compressed-1024x683.jpg",category:"Producto, proceso o servicio innovador",topic:"Transformaci\xf3n tecnol\xf3gica",ua:["Facultad de Arquitectura, Urbanismo y Dise\xf1o"],year:"2024",position:null,team:["Alvarez Vallero In\xe9s","Flavia Andrea Gandini","Priscila Judith Guevara"],desc:"PRO.TEC es una barrera f\xedsica modular dise\xf1ada para reducir el 20% de desperdicio que generan las silobolsas de autoconsumo ganadero. Facilita la apertura frontal y lateral del forraje para bovinos y ovinos. Es liviana, durable, f\xe1cil de montar y transportar, y adaptable a distintos sistemas productivos sin necesidad de mantenimiento."},{title:"Dise\xf1o de sistemas log\xedsticos urbanos para la distribuci\xf3n de mercanc\xedas",short_name:"Log\xedstica urbana para distribuir mercanc\xedas",url:"https://uncinnova.unc.edu.ar/diseno-de-sistemas-logisticos-urbanos-para-la-distribucion-de-mercancias/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/sistLogisticos_portada-min-1024x527.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Transformaci\xf3n tecnol\xf3gica",ua:["Facultad de Arquitectura, Urbanismo y Dise\xf1o"],year:"2024",position:null,team:["Mateo Gamba"],desc:"Esta metodolog\xeda combina an\xe1lisis geoespacial, estudio de demanda hist\xf3rica y proyecci\xf3n futura de env\xedos para dise\xf1ar redes de distribuci\xf3n urbana de paqueter\xeda e-commerce. Posiblita determinar la cantidad, tama\xf1o, localizaci\xf3n \xf3ptima de instalaciones y el tipo de veh\xedculo m\xe1s adecuado para atender la demanda actual y futura de manera eficiente y con emisiones cero."},{title:"Estamp.ar | Certificaci\xf3n, resguardo y distribuci\xf3n de archivos en Blockchain",short_name:"Certificaci\xf3n, resguardo y distribuci\xf3n de archivos en Blockchain",url:"https://uncinnova.unc.edu.ar/estamp-ar-certificacion-resguardo-y-distribucion-de-archivos-en-blockchain/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/PORTADA8-1024x684.jpg",category:"Producto, proceso o servicio innovador",topic:"Transformaci\xf3n tecnol\xf3gica",ua:["Facultad de Ciencias Econ\xf3micas"],year:"2024",position:null,team:["Pedro Nicol\xe1s Tapia"],desc:"Estamp.ar es una Plataforma que usa tecnolog\xedas blockchain —Bitcoin, Ethereum, IPFS y Matic— para garantizar la inmutabilidad y autenticidad de archivos digitales. Genera tokens no fungibles (NFTs) que certifican la propiedad y originalidad de cada documento. Est\xe1 dirigida a m\xfaltiples sectores, desde el gubernamental hasta el empresarial y acad\xe9mico, donde la integridad documental es cr\xedtica."},{title:"Bircle | Cobros \xe1giles con IA para PYMES",short_name:"Cobros \xe1giles con IA para PYMES",url:"https://uncinnova.unc.edu.ar/bircle-cobros-agiles-con-ia-para-pymes/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/1.9-PORTADA-01-1024x512.jpg",topic:"Transformaci\xf3n tecnol\xf3gica",category:"Producto, proceso o servicio innovador",ua:["Facultad de Derecho"],year:"2024",position:null,team:["Jos\xe9 Romero Victorica","Marcos Lozada Freytes","Francisco Piantoni Vera"],desc:"Bircle es un software que automatiza la gesti\xf3n de pagos recurrentes en PYMES mediante inteligencia artificial conversacional. Se adapta de forma din\xe1mica a las circunstancias de cada cliente moroso, con una aproximaci\xf3n respetuosa que cuida la reputaci\xf3n de la marca. Apunta a reducir los costos de cobranza y aumentar la recuperaci\xf3n de deudas sin afectar el v\xednculo comercial."},{title:"\xcdndice de exposici\xf3n a cr\xedmenes violentos en C\xf3rdoba",short_name:"\xcdndice de exposici\xf3n a cr\xedmenes violentos en C\xf3rdoba",url:"https://uncinnova.unc.edu.ar/indice-de-exposicion-a-crimenes-violentos-en-cordoba/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/1.8-PORTADA-01-1024x512.jpg",topic:"Transformaci\xf3n tecnol\xf3gica",category:"Producto, proceso o servicio innovador",ua:["Programa de Prevenci\xf3n en Problem\xe1ticas de Violencia de la Facultad de Psicolog\xeda","Instituto de Estad\xedstica y Demograf\xeda de la Facultad de Ciencias Econ\xf3micas","Observatorio de Violencias y Seguridad Humana de la Facultad de Psicolog\xeda."],year:"2024",position:null,team:["Lucio Ramos","Mar\xeda In\xe9s Stimolo","Mariana Funes"],desc:"Este proyecto adapta el \xcdndice de Exposici\xf3n a Cr\xedmenes Violentos del Instituto Sou da Paz de San Pablo a la realidad de C\xf3rdoba, combinando datos de homicidios, delitos sexuales y robos del per\xedodo 2019-2023. Se presenta en un tablero din\xe1mico que permite visualizar la evoluci\xf3n territorial del delito. El fin es ofrecer insumos basados en evidencia para el dise\xf1o de pol\xedticas p\xfablicas de seguridad."},{title:"Nano-Control: estandarizaci\xf3n en transferencia de membranas",short_name:"Nano-Control | Estandarizaci\xf3n en transferencia de membranas",url:"https://uncinnova.unc.edu.ar/nano-control-estandarizacion-en-transferencia-de-membranas/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/1.7-PORTADA-01-1024x512.jpg",topic:"Transformaci\xf3n tecnol\xf3gica",category:"Producto, proceso o servicio innovador",ua:["Facultad de Arquitectura, Urbanismo y Dise\xf1o"],year:"2024",position:null,team:["Prieto Sofia","Domke Germ\xe1n","Cuesta M\xe1ximo"],desc:"Nano-Control surge de la colaboraci\xf3n entre dise\xf1o industrial y biof\xedsica para desarrollar un instrumento que transfiere membranas a sustratos hidrof\xf3bicos de manera estandarizada. Permite obtener mayor cantidad de muestras, en menos tiempo y con mayor precisi\xf3n, preserv\xe1ndolas h\xfamedas tras la transferencia. De esa manera, estandariza el muestreo, conservaci\xf3n y transporte de muestras en investigaci\xf3n cient\xedfica."},{title:"Aplicaci\xf3n de Industria 4.0 en planificaci\xf3n de producci\xf3n",short_name:"Aplicaci\xf3n de Industria 4.0 en planificaci\xf3n de producci\xf3n",url:"https://uncinnova.unc.edu.ar/aplicacion-de-industria-4-0-en-planificacion-de-produccion/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/1.6-PORTADA-01-1024x512.jpg",topic:"Transformaci\xf3n tecnol\xf3gica",category:"Producto, proceso o servicio innovador",ua:["Universidad Nacional de C\xf3rdoba (UNC)","Consejo Nacional de Investigaciones Cient\xedficas y T\xe9cnicas (CONICET)","Universidad Tecnol\xf3gica Nacional (UTN)","Fundaci\xf3n Sadosky"],year:"2024",position:null,team:["UNC","Conicet","UTN"],desc:"Esta aplicaci\xf3n web emplea tecnolog\xedas de Industria 4.0 e inteligencia artificial para generar agendas prescriptivas de producci\xf3n a corto plazo, optimizar m\xe9tricas y proveer tableros de anal\xedtica descriptiva. Est\xe1 pensada especialmente para PYMEs de bajo presupuesto que buscan transformaci\xf3n digital. Se basa en software de licencia libre y permite comparar escenarios alternativos antes de tomar decisiones en planta."},{title:"Plataformas digitales y derechos | Complejidades y desaf\xedos para la gobernanza de la transformaci\xf3n digital",short_name:"Transformaci\xf3n digital | Plataformas digitales y derechos",url:"https://uncinnova.unc.edu.ar/plataformas-digitales-y-derechos-complejidades-y-desafios-para-la-gobernanza-de-la-transformacion-digital/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/1.5-PORTADA-1-1024x512.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Transformaci\xf3n tecnol\xf3gica",ua:["Facultad de Ciencias Sociales"],year:"2024",position:null,team:["Nicol\xe1s Gim\xe9nez Venezia","Pilar Anastasia Gonz\xe1les","Macarena Roldan","Mat\xedas Parano","Isabella De Marchi Luciana Almada","Natalia Debora Gonz\xe1lez","Sofia Rizzo","Francisco Paviglianiti","Lucia Victoria M\xfcller","Mar\xeda Guadalupe Barrios","Micaela A. Arnaudo","Seraf\xedn Gonz\xe1lez","Pablo Oscar Salinas","Emilia Marchionatti","Miranda Schilling","Gino Polizzi","Lena Ruth Garbovetzky"],desc:"Este proyecto construy\xf3 una base de datos —mediante triangulaci\xf3n de m\xe9todos cuantitativos y cualitativos— que caracteriza los circuitos de accesibilidad a plataformas digitales en distintos sectores sociales de C\xf3rdoba. La idea es que esa informaci\xf3n oriente pol\xedticas p\xfablicas que garanticen el acceso igualitario a servicios y derechos mediados por tecnolog\xeda, considerando diferencias generacionales, culturales y sociales."},{title:"FastMapping | Software de uso libre para la agricultura de precisi\xf3n",short_name:"FastMapping | Software para la agricultura de precisi\xf3n",url:"https://uncinnova.unc.edu.ar/fastmapping-software-de-uso-libre-para-la-agricultura-de-precision/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/PORTADA6-1024x577.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Transformaci\xf3n tecnol\xf3gica",ua:["Facultad de Ciencias Agropecuarias de la Universidad Nacional de C\xf3rdoba (UNC)","Consejo Nacional de Investigaciones Cient\xedficas y T\xe9cnicas (CONICET)"],year:"2024",position:null,team:["Mariano C\xf3rdoba","Pablo Paccioretti","M\xf3nica Balzarini"],desc:"FastMapping es una herramienta de c\xf3digo abierto que permite a productores sin formaci\xf3n t\xe9cnica procesar datos georreferenciados del suelo, generar mapas de variaci\xf3n espacial continua y delimitar zonas homog\xe9neas para el manejo diferenciado de lotes agr\xedcolas. Integra algoritmos de aprendizaje autom\xe1tico, protocolos estad\xedsticos validados y an\xe1lisis de ensayos de dosis variables en una sola aplicaci\xf3n de escritorio."},{title:"Nanofiltros inteligentes para purificaci\xf3n de agua",short_name:"Nanofiltros inteligentes para purificaci\xf3n de agua",url:"https://uncinnova.unc.edu.ar/nanofiltros-inteligentes-con-ia-para-purificacion-de-agua/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/1.2-PORTADA-1024x512.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Transformaci\xf3n tecnol\xf3gica",ua:["Facultad de Matem\xe1tica, Astronom\xeda, F\xedsica y Computaci\xf3n"],year:"2024",position:null,team:["Noelia Bajales Luna","Nicol\xe1s Mart\xedn","Candelaria Mart\xednez","Agustina Crucianelli","Sof\xeda Sena"],desc:"Esta iniciativa desarrolla filtros de agua controlados por machine learning que integran ultrasensibilidad, portabilidad, selecci\xf3n inteligente y propiedades antimicrobianas en una \xfanica plataforma. La meta es que puedan incorporarse en equipos de purificaci\xf3n o sistemas de filtrado y sensado a escala nano y microm\xe9trica, para contribuir a la remediaci\xf3n ambiental en contextos de escasez o contaminaci\xf3n h\xeddrica."},{title:"Torneo Cient\xedfico Universitario",short_name:"Torneo Cient\xedfico Universitario",url:"https://uncinnova.unc.edu.ar/torneo-cientifico-universitario/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/PORTADA-TOSOLINO-1024x395.jpg",topic:"Equidad, inclusi\xf3n y acceso al conocimiento",category:"Producto, proceso o servicio innovador",ua:["Ministerio de Ciencia y Tecnolog\xeda de la provincia de C\xf3rdoba,","Facultades de la Universidad Nacional de C\xf3rdoba","Universidad Nacional de R\xedo Cuarto","Universidad Nacional del Litoral"],year:"2024",position:null,team:["Lucas Ticiano Tosolino","Jimena Aylen Dornauf","Lucila Riegler","Joaqu\xedn Ferreyra"],desc:"El TCU es una competencia virtual y presencial, libre y gratuita, que promueve las ciencias naturales entre estudiantes universitarios de carreras STEM de todo el pa\xeds. Incluye instancias individuales de evaluaci\xf3n, producci\xf3n de comunicaci\xf3n cient\xedfica grupal y resoluci\xf3n de desaf\xedos pr\xe1cticos. Busca reducir la deserci\xf3n, potenciar vocaciones cient\xedficas y fomentar la interconexi\xf3n entre j\xf3venes universitarios de distintas provincias."},{title:"Herramientas de intervenci\xf3n para la econom\xeda popular de C\xf3rdoba",short_name:"Herramientas para la econom\xeda popular de C\xf3rdoba",url:"https://uncinnova.unc.edu.ar/herramientas-de-intervencion-para-la-economia-popular-de-cordoba/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/TOMATIS-PORTADA-1024x683.jpg",topic:"Equidad, inclusi\xf3n y acceso al conocimiento",category:"Investigaci\xf3n o desarrollo aplicable",ua:["Facultad de Ciencias Econ\xf3micas","Facultades de Filosof\xeda y Humanidades","Facultad de Ciencias Sociales","Facultad de Ciencias de la Comunicaci\xf3n","Ciencias Humanas UNRC","Agronom\xeda UNRC","Veterinaria UNRC","IDACOR-MA – Conicet UNC","Instituto de Investigaciones sociales, territoriales y educativas (Conicet-UNRC)","Programa de Fortalecimiento de la Econom\xeda Popular (PFEP) de la Secretar\xeda de Econom\xeda Social del Ministerio de Desarrollo Social y Promoci\xf3n del Empleo de C\xf3rdoba","Mesa Inter-institucional de Ciencia y Tecnolog\xeda Social en Econom\xeda Popular"],year:"2024",position:null,team:["Julieta Quir\xf3s","Karina Lorena Tomatis","Claudia Kenbel","Mar\xeda Victoria Perissinotti"],desc:"ImpaCT.AR en Econom\xeda Popular-C\xf3rdoba es un proyecto de investigaci\xf3n y transferencia que genera conocimiento y herramientas para fortalecer la gesti\xf3n p\xfablica provincial orientada a quienes trabajan en la econom\xeda informal. Caracteriz\xf3 la realidad del sector, produjo materiales audiovisuales de sensibilizaci\xf3n y dise\xf1\xf3 protocolos de trabajo de campo. Su fin es que los datos producidos orienten pol\xedticas de inclusi\xf3n, desarrollo econ\xf3mico y social basadas en evidencia."},{title:"Nataci\xf3n para personas con par\xe1lisis cerebral",short_name:"Accesorio de nataci\xf3n para personas con par\xe1lisis cerebral",url:"https://uncinnova.unc.edu.ar/accesorio-de-natacion-para-personas-con-paralisis-cerebral/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/OLOCCO-PORTADA-2-1024x384.jpg",topic:"Equidad, inclusi\xf3n y acceso al conocimiento",category:"Producto, proceso o servicio innovador",ua:["Facultad de Arquitectura, Urbanismo y Dise\xf1o"],year:"2024",position:null,team:["Machado Ana Laura","Olocco Lara In\xe9s","Paez Laura Micaela"],desc:"Consiste en el dise\xf1o un accesorio de flotaci\xf3n y estabilidad para personas con par\xe1lisis cerebral que presentan entre un 70% y 80% de espasticidad. Apoya la zona cervical para evitar rotaciones de cabeza y contiene la cadera, mientras libera los om\xf3platos para posibilitar las brazadas. Reduce los riesgos de broncoaspiraci\xf3n, disminuye la carga sobre el docente y promueve la autonom\xeda en el aprendizaje de la nataci\xf3n."},{title:"Sistema de sujeci\xf3n para celdas de Franz",short_name:"Sistema de sujeci\xf3n para celdas de Franz",url:"https://uncinnova.unc.edu.ar/sistema-de-sujecion-para-celdas-de-franz/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/LONGHI-PORTADA-VERTICAL-1024x384.jpg",topic:"Equidad, inclusi\xf3n y acceso al conocimiento",category:"Producto, proceso o servicio innovador",ua:["Facultad de Ciencias Qu\xedmicas"],year:"2024",position:null,team:["Carolina Aloisio","Alfonsina Ester Andreatta","Marcela Longhi"],desc:"Se trata de un sistema de cierre y sujeci\xf3n individual para celdas de difusi\xf3n de Franz, que son el dispositivo recomendado por la FDA para medir la permeaci\xf3n cut\xe1nea de semis\xf3lidos. El sistema es sencillo, reutilizable y econ\xf3mico, ya que puede fabricarse con materiales recuperados o de descarte. Cubre una necesidad que los equipos comerciales de alto costo no resuelven de manera accesible."},{title:"La Ciudad de las Mujeres",short_name:"La Ciudad de las Mujeres",url:"https://uncinnova.unc.edu.ar/la-ciudad-de-las-mujeres/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/PORTADA-CHIABRANDO-18-1024x384.jpg",topic:"Equidad, inclusi\xf3n y acceso al conocimiento",category:"Producto, proceso o servicio innovador",ua:["Facultad de Filosof\xeda y Humanidades"],year:"2024",position:null,team:["Victoria Chabrando","Ver\xf3nica Ar\xe1oz","Emilia Balacco","Roc\xedo Lopez Arzuaga"],desc:"Este proyecto relev\xf3 que el 93% de las calles de C\xf3rdoba llevan nombres masculinos y construy\xf3 una base de datos abierta con mujeres y diversidades destacadas en la vida pol\xedtica, art\xedstica, deportiva y educativa de la ciudad, desde la \xe9poca colonial hasta hoy. Su finalidad es revertir esa desigualdad en el espacio p\xfablico mediante carteler\xeda, mapas interactivos, podcasts y recorridos tur\xedsticos. Ya impuls\xf3 la modificaci\xf3n de una ordenanza municipal que exige paridad de g\xe9nero en la nomenclatura de nuevos espacios p\xfablicos."},{title:"Cubo de Rubik inclusivo",short_name:"Cubo de Rubik inclusivo",url:"https://uncinnova.unc.edu.ar/cubo-de-rubik-inclusivo/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/BARRETO-PORTADA--1024x562.jpg",topic:"Equidad, inclusi\xf3n y acceso al conocimiento",category:"Producto, proceso o servicio innovador",ua:["Facultad de Ciencias Exactas, F\xedsicas y Naturales"],year:"2024",position:null,team:["Barreto, Ezequiel Nicol\xe1s","Bertello, Elda Rosal\xeda","Ferrero, Stefan\xeda Mail\xe9n","Worst Lobo, Liliane"],desc:"Es un prototipo de Cubo de Rubik adaptado para personas con motricidad fina comprometida por enfermedades o condiciones especiales. Reemplaza la manipulaci\xf3n directa del cubo por un teclado de grandes dimensiones cuyas teclas accionan los movimientos de cada capa. De ese modo, estas personas acceden a los beneficios cognitivos del rompecabezas, con aplicaciones en terapia ocupacional, educaci\xf3n inclusiva y actividades recreativas."},{title:"Del “dec\xed que no…” al “\xbfsab\xedas que… ?”: una intervenci\xf3n para reducir el consumo de alcohol en adolescentes",short_name:"Intervenci\xf3n para reducir el consumo de alcohol en adolescentes",url:"https://uncinnova.unc.edu.ar/del-deci-que-no-al-sabias-que-una-intervencion-para-reducir-el-consumo-de-alcohol-en-adolescentes/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/PORTADA-18-1024x395.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Salud humana",ua:["Facultad de Psicolog\xeda UNC","Instituto Ferreyra","Instituto de Investigaciones Psicol\xf3gicas","Secretar\xeda de Prevenci\xf3n y Asistencia de las Adicciones - Gobierno de C\xf3rdoba","Ministerio de Salud, Ministerio de Educaci\xf3n, Ministerio de Ciencia y Tecnolog\xeda de la Provincia de C\xf3rdoba","Escuelas p\xfablicas y privadas, clubes deportivos"],year:"2024",position:null,team:["Ricardo Pautassi","Angelina Pilatti","Yanina Michelini","Gabriela Rivarola Montejano","Dar\xedo Gigena-Parker","Pablo Bonino","Manuel Badino"],desc:"\xab\xbfSab\xedas Qu\xe9…?\xbb es una intervenci\xf3n breve basada en el modelo de normas sociales para retrasar el inicio o ralentizar la progresi\xf3n del consumo de alcohol en adolescentes. Su meta es corregir la tendencia de los j\xf3venes a sobreestimar el consumo de sus pares. Constituye la primera aplicaci\xf3n de un programa de estas caracter\xedsticas en Argentina, y ya fue implementada en C\xf3rdoba y Montevideo, con un manual de acceso abierto para su replicaci\xf3n."},{title:"Parches autoaplicables con tecnolog\xeda de microagujas para tratamiento de afecciones dermocosm\xe9ticas",short_name:"Parches autoaplicables con tecnolog\xeda de microagujas",url:"https://uncinnova.unc.edu.ar/parches-autoaplicables-con-tecnologia-de-microagujas-para-tratamiento-de-afecciones-dermocosmeticas/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/roldan-valentin-1024x666.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Salud humana",ua:["Facultad de Ciencias Qu\xedmicas"],year:"2024",position:null,team:["Daniela Alejandra Quinteros","Sofia Mickaela Martinez","Valentin Roldan Julian"],desc:"Desarrollo de parches de microagujas autoaplicables, fabricados con impresi\xf3n 3D y micromoldeo. Las microagujas penetran la capa epid\xe9rmica sin causar dolor y liberan principios activos –como \xe1cido hialur\xf3nico– directamente en el sitio de acci\xf3n. Se adaptan a la zona espec\xedfica de piel a tratar y son m\xe1s eficaces que las cremas convencionales. No existe en Latinoam\xe9rica un producto con estas caracter\xedsticas y aprobaci\xf3n de la FDA."},{title:"Secuenciaci\xf3n masiva y bioinform\xe1tica en el diagn\xf3stico molecular de enfermedades poco frecuentes",short_name:"Diagn\xf3stico molecular de enfermedades poco frecuentes",url:"https://uncinnova.unc.edu.ar/secuenciacion-masiva-y-bioinformatica-en-el-diagnostico-molecular-de-enfermedades-poco-frecuentes/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/portada-nicola-1024x681.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Salud humana",ua:["Facultad de Ciencias Qu\xedmicas"],year:"2024",position:null,team:["Juan Pablo Nicola","Sof\xeda Savy"],desc:"Esta iniciativa implementa la secuenciaci\xf3n del exoma completo combinada con bioinform\xe1tica para diagnosticar enfermedades poco frecuentes en pacientes pedi\xe1tricos. En 90 casos estudiados, logr\xf3 una eficiencia del 56%. Apunta a crear una empresa de base tecnol\xf3gica que ofrezca este servicio en C\xf3rdoba. La visi\xf3n es democratizar el acceso a diagn\xf3sticos de alta complejidad para toda la poblaci\xf3n, con criterio de equidad."},{title:"Protocolo para prevenci\xf3n de infecciones de transmisi\xf3n sexual en gestantes y reci\xe9n nacidos",short_name:"Prevenci\xf3n de infecciones de transmisi\xf3n sexual en gestantes y beb\xe9s",url:"https://uncinnova.unc.edu.ar/protocolo-para-prevencion-de-infecciones-de-transmision-sexual-en-gestantes-y-recien-nacidos/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/CUFFINI-PORTADA--1024x683.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Salud humana",ua:["Facultad de Ciencias M\xe9dicas","Hospital Universitario de Maternidad y Neonatolog\xeda&nbsp;","Hospital Materno Provincial “Dr. R.F. Lucini”,","Instituto de Virolog\xeda “Dr. J. M. Vanella”-FCM-UNC.",""],year:"2024",position:null,team:["Andrea Sala","Jessica Mosmann","Fernando Venezuela","Sof\xeda Zayas"],desc:"Este trabajo estudia la prevalencia y epidemiolog\xeda molecular de &quot;Chlamydia trachomatis&quot; en 300 gestantes en el tercer trimestre y en sus reci\xe9n nacidos, en dos maternidades de C\xf3rdoba. Ante un resultado positivo, se indica tratamiento y test de cura. El fin es generar datos locales sobre variabilidad gen\xe9tica y factores de riesgo que orienten pol\xedticas de salud p\xfablica para prevenir la transmisi\xf3n vertical y sus complicaciones neonatales."},{title:"Protocolo para prevenci\xf3n del s\xedndrome confusional agudo",short_name:"Protocolo para prevenci\xf3n del s\xedndrome confusional agudo",url:"https://uncinnova.unc.edu.ar/protocolo-para-prevencion-del-sindrome-confusional-agudo/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/PORTADA-1-1024x576.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Salud humana",ua:["Facultad de Ciencias M\xe9dicas"],year:"2024",position:null,team:["Roc\xedo Contreras Roqu\xe9","Mar\xeda Jos\xe9 Rueda","Carolina Bustos Fierro","Breda Andrea","Periolo Angelina","Florencia Fern\xe1ndez","Pulido Paula","Boni Liliana","Franco Paola","Melian Julio","Conca Pablo"],desc:"Este proyecto establece un protocolo de evaluaci\xf3n y abordaje temprano del S\xedndrome Confusional Agudo en adultos mayores internados, adaptado a los recursos de hospitales p\xfablicos de tercer nivel en Argentina. Integra intervenciones no farmacol\xf3gicas como estimulaci\xf3n cognitiva, kin\xe9sica y contenci\xf3n afectiva. El prop\xf3sito es reducir el uso de sedantes y restricciones f\xedsicas, y mejorar la calidad de vida durante la internaci\xf3n."},{title:"Aprovechamiento de sangre ovina en pastas frescas artesanales de alto valor nutritivo",short_name:"Aprovechamiento de sangre ovina en pastas frescas",url:"https://uncinnova.unc.edu.ar/aprovechamiento-de-sangre-ovina-en-pastas-frescas-artesanales-de-alto-valor-nutritivo/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/06/ovino_5-1024x682.jpg",category:"Producto, proceso o servicio innovador",topic:"Salud humana",ua:["Facultad de Ciencias M\xe9dicas UNC","Facultad de Agronom\xeda","Escuela de Nutrici\xf3n de la UNC","IPEA N\xb0217","IPETyM N\xb074."],year:"2024",position:null,team:["Agust\xedn Banno","Mar\xeda Luz Borgonovo","Mariela Volont\xe9","Romina Bocco"],desc:"Formulaci\xf3n de pastas frescas artesanales con un 10% de harina de sangre ovina, un subproducto del faenamiento que habitualmente se descarta. El producto resultante eleva considerablemente el contenido proteico y ferroso, cumple los est\xe1ndares industriales de calidad y es de bajo costo. Surgi\xf3 de una articulaci\xf3n entre la UNC y dos escuelas t\xe9cnicas de Villa del Totoral, con potencial para formalizar un canal de venta directa del productor al consumidor."},{title:"Nutri2: Investigaci\xf3n en nutrici\xf3n animal para una ganader\xeda sustentable",short_name:"Nutrici\xf3n animal para una ganader\xeda sustentable",url:"https://uncinnova.unc.edu.ar/nutri2-investigacion-en-nutricion-animal-para-una-ganaderia-sustentable/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/nutridos_PORTADA.jpg",topic:"Conservaci\xf3n de la biodiversidad y cambio clim\xe1tico",category:"Investigaci\xf3n o desarrollo aplicable",ua:["Facultad de Ciencias Agropecuarias"],year:"2024",position:null,team:["Marcos Zenobi","Soraya Salloum","Catalina Boetto","Alejandra Cabanillas","Gonzalo Luna","Rub\xe9n Gim\xe9nez"],desc:"Nutri2 apunta a revitalizar y expandir la producci\xf3n de conocimiento en nutrici\xf3n bovina en Argentina, un \xe1rea de escasa investigaci\xf3n aplicada, y transferirla a productores y empresas del sector. Cuenta con infraestructura de vanguardia como comederos inteligentes y una lecher\xeda experimental. Su enfoque integral articula productividad, reducci\xf3n de emisiones de gases de efecto invernadero y sostenibilidad a largo plazo de la ganader\xeda cordobesa."},{title:"Elaboraci\xf3n de sopas saludables a partir de hortalizas de reducido valor comercial",short_name:"Sopas con hortalizas de reducido valor comercial",url:"https://uncinnova.unc.edu.ar/elaboracion-de-sopas-saludables-a-partir-de-hortalizas-de-reducido-valor-comercial/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/3.6-PORTADA-1024x512.jpg",topic:"Bioeconom\xeda",category:"Investigaci\xf3n o desarrollo aplicable",ua:["Facultad de Ciencias M\xe9dicas"],year:"2024",position:null,team:["Ana Laura S\xe1nchez Salamanca","Natalia Cervilla","Claudia Albrecht","Paula Lucia Andres","Mar\xeda Jos\xe9 Leguiza","Florencia Santill\xe1n"],desc:"Consiste en el dise\xf1o de sopas listas para consumir a partir de frutas y hortalizas recuperadas del Mercado de Abasto de C\xf3rdoba por la Fundaci\xf3n Banco de Alimentos, vegetales descartados por no cumplir est\xe1ndares est\xe9ticos de venta. Sin aditivos, de bajo costo y envasables, los productos tienen como fin proveer alimentaci\xf3n fresca y saludable a comunidades vulnerables, al tiempo que reduce el desperdicio de alimentos."},{title:"Desarrollo de micropart\xedculas porosas para la carga y protecci\xf3n de compuestos bioactivos",short_name:"Micropart\xedculas porosas para compuestos bioactivos",url:"https://uncinnova.unc.edu.ar/desarrollo-de-microparticulas-porosas-para-la-carga-y-proteccion-de-compuestos-bioactivos/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/microparticulas_PORTADA-1024x768.jpg",topic:"Bioeconom\xeda",category:"Investigaci\xf3n o desarrollo aplicable",ua:["Facultad de Ciencias Exactas, F\xedsicas y Naturales"],year:"2024",position:null,team:["Roxana Ver\xf3nica Piloni","Gabriela Noel Barrera","Gabriela Bord\xf3n","Pablo Mart\xedn Palavecino","Esteban Carrillo","Mar\xeda Cecilia Penci","Marcela Lilian Mart\xednez"],desc:"Esta investigaci\xf3n se enfoca en la obtenci\xf3n de matrices de almid\xf3n poroso modificado mediante m\xe9todos enzim\xe1ticos y f\xedsicos. Las matrices permiten encapsular vitaminas, antioxidantes y \xe1cidos grasos esenciales, para protegerlos de la degradaci\xf3n y controlar su liberaci\xf3n. El objetivo de este estudio es evaluar sus propiedades estructurales e impregnaci\xf3n con bioactivos de inter\xe9s. Tienen potencial de aplicaci\xf3n en alimentos funcionales, biorremediaci\xf3n y veh\xedculos farmac\xe9uticos."},{title:"Desarrollo de biopl\xe1sticos ecol\xf3gicos a partir de efluentes de tambo",short_name:"Biopl\xe1sticos a partir de efluentes de tambo",url:"https://uncinnova.unc.edu.ar/desarrollo-de-bioplasticos-ecologicos-a-partir-de-efluentes-de-tambo/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/3.4-PORTADA-1024x512.jpg",topic:"Bioeconom\xeda",category:"Investigaci\xf3n o desarrollo aplicable",ua:["Facultad de Ciencias Agropecuarias"],year:"2024",position:null,team:["Mar\xeda Paula Mart\xedn","Carolina Merlo","Carolina V\xe1zquez","Mariela Archilla","Romina Pizzolitto","Ibrahim Ayoub"],desc:"Esta propuesta busca un proceso biotecnol\xf3gico que use los efluentes de tambo —40 millones de litros diarios en C\xf3rdoba— como fuente de carbono para que microorganismos produzcan PHAs, biopl\xe1sticos biodegradables y compostables. As\xed se convierte un residuo contaminante en materia prima de bajo costo. Los biopl\xe1sticos obtenidos pueden utilizarse en envases de alimentos, aditivos para biocombustibles e impresi\xf3n 3D."},{title:"Evaluaci\xf3n de la sustentabilidad de un \xe1rea agroecol\xf3gica",short_name:"Evaluaci\xf3n de la sustentabilidad de un \xe1rea agroecol\xf3gica",url:"https://uncinnova.unc.edu.ar/evaluacion-de-la-sustentabilidad-de-un-area-agroecologica/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/sustentabilidad_PORTADA.jpg",topic:"Conservaci\xf3n de la biodiversidad y cambio clim\xe1tico",category:"Investigaci\xf3n o desarrollo aplicable",ua:["Facultad de Ciencias Agropecuarias"],year:"2024",position:null,team:["Luciano Locati","Luciana Suez","Jos\xe9 Molina","Lucrecia Estigarribia","Hugo Vaccarello","Joaqu\xedn Herrero |Diego Cabral","Javier Quinteros"],desc:"Este proyecto eval\xfaa la sustentabilidad de un \xe1rea agroecol\xf3gica experimental en el Campo Escuela de la Facultad de Ciencias Agropecuarias de la UNC, usando la metodolog\xeda MESMIS y ensayos con bioinsumos. El prop\xf3sito es que funcione como caso testigo accesible a productores, estudiantes y escuelas para alentar transiciones agroecol\xf3gicas m\xe1s resilientes frente al cambio clim\xe1tico en la regi\xf3n hort\xedcola de C\xf3rdoba."},{title:"En el Monte: una experiencia del co terrar en realidad virtual",short_name:"Co terrar en la realidad virtual",url:"https://uncinnova.unc.edu.ar/en-el-monte-una-experiencia-del-co-terrar-en-realidad-virtual/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/En-el-Monte_PORTADA-1024x576.jpg",topic:"Conservaci\xf3n de la biodiversidad y cambio clim\xe1tico",category:"Producto, proceso o servicio innovador",ua:["Facultad de Artes"],year:"2024",position:null,team:["M\xf3nica Jacobo","Natalia Estarellas","Sergio Poblete Barbero","Dylan Martin","Nahir Dahbar","Dante Demarchi Oliveira","Mara Blasco","Alma Martina Rolan Torres"],desc:"\xabEn el Monte\xbb es una obra de realidad virtual que permite vivenciar de forma inmersiva el proceso de polinizaci\xf3n entre plantas nativas de las serran\xedas cordobesas. Al trasladar al usuario al interior del monte como si fuera un polinizador, busca generar un compromiso afectivo con la naturaleza, sensibilizar sobre la importancia de los polinizadores y promover el turismo sustentable como alternativa a la percepci\xf3n depredadora del entorno."},{title:"Proyecto COCO: cultivo sostenible del hongo del coco",short_name:"Cultivo sostenible del hongo del coco",url:"https://uncinnova.unc.edu.ar/proyecto-coco-cultivo-sostenible-del-hongo-del-coco/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/ProyectoCOCO_PORTADA-min-1024x1024.jpg",topic:"Conservaci\xf3n de la biodiversidad y cambio clim\xe1tico",category:"Producto, proceso o servicio innovador",ua:["Facultad de Ciencias Agropecuarias"],year:"2024",position:null,team:["Gerardo Robledo","Alejandro Perez","Ariel E. Ortiz","Lara Thornton","Enzo Cristaldo","Georgina Domini","Geraldine Delacroix","Sol Auchterlonie"],desc:"El hongo del coco (Phlebopus bruchii), especie end\xe9mica y en peligro cr\xedtico de extinci\xf3n del Bosque Serrano cordob\xe9s, es actualmente sobreexplotado por la industria gastron\xf3mica. Este proyecto busca desarrollar una unidad modelo de cultivo, replicable y escalable, para producirlo todo el a\xf1o, con bajo costo y sin conocimientos especializados. Apunta a aliviar la presi\xf3n sobre la especie, reintroducirla en su ecosistema y fomentar microemprendimientos locales."},{title:"Alimentos saludables a partir de ma\xedces mejorados",short_name:"Alimentos saludables a partir de ma\xedces mejorados",url:"https://uncinnova.unc.edu.ar/alimentos-saludables-a-partir-de-maices-mejorados/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/PORTADA_MaicesMejorados-1024x697.jpg",topic:"Bioeconom\xeda",category:"Producto, proceso o servicio innovador",ua:["Facultad de Ciencias Agropecuarias"],year:"2024",position:null,team:["Pablo Sebasti\xe1n Mansilla","Candela Paesani","Luisina Monsierra","Agustina del Pilar Bertola","Nicol\xe1s Bongianino"],desc:"Evaluaci\xf3n de variedades de ma\xedz morado y colorado de polinizaci\xf3n libre, desarrolladas en la UNC, para producir alimentos farin\xe1ceos sin gluten, como cereales de desayuno y polentas. Analiza aptitud industrial, calidad nutricional, biodisponibilidad de antioxidantes y aceptabilidad sensorial. Adem\xe1s de generar productos saludables, permite que los productores guarden semillas y reduzcan su dependencia de empresas semilleras."},{title:"Sistema de Inmersi\xf3n Temporal FCA | Gesti\xf3n eficiente de agua y nutrientes aplicada a la multiplicaci\xf3n de plantas",short_name:"Gesti\xf3n de agua y nutrientes en la multiplicaci\xf3n de plantas",url:"https://uncinnova.unc.edu.ar/sistema-de-inmersion-temporal-fca-gestion-eficiente-de-agua-y-nutrientes-aplicada-a-la-multiplicacion-de-plantas/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/PORTADA-Delfino-1024x683.jpg",topic:"Bioeconom\xeda",category:"Producto, proceso o servicio innovador",ua:["Facultad de Ciencias Agropecuarias"],year:"2024",position:null,team:["Pablo Mario Delfino","Ferando Ezequiel Dell Inocenti","Cristina Flamarique","Paula Bima"],desc:"El SIT FCA es un sistema de cultivo controlado que alterna ciclos de inmersi\xf3n en soluci\xf3n nutritiva con exposici\xf3n al aire, regulados electr\xf3nicamente, para multiplicar plantas de forma r\xe1pida, econ\xf3mica y libre de contaminantes. Fabricado con materiales accesibles y de bajo costo, garantiza que los ejemplares obtenidos sean gen\xe9ticamente id\xe9nticos a la planta madre. Su dise\xf1o compacto lo hace apto tanto para investigaci\xf3n como para producci\xf3n comercial."},{title:"Microc\xe1psulas con antioxidantes de piel de man\xed para conservar de alimentos",short_name:"Microc\xe1psulas con antioxidantes de piel de man\xed",url:"https://uncinnova.unc.edu.ar/microcapsulas-con-antioxidantes-de-piel-de-mani-para-conservar-de-alimentos/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/PORTADA-Microcapsulas-piel-de-mani.jpg",topic:"Bioeconom\xeda",category:"Investigaci\xf3n o desarrollo aplicable",ua:["Facultad de Ciencias Agropecuarias"],year:"2024",position:null,team:["Antonella Bergesse","Ornella Camiletti","Judith Lambir Jacobo","Liliana Ryan","Valeria Nepote"],desc:"Desarrollo de microc\xe1psulas de polifenoles extra\xeddos del tegumento de man\xed —subproducto residual de la industria— para incorporarlos como conservantes naturales en alimentos. La microencapsulaci\xf3n protege los compuestos de la luz, el calor y el ox\xedgeno, y permite su liberaci\xf3n controlada. El fin es aumentar la vida \xfatil de los alimentos, reemplazar aditivos sint\xe9ticos y agregar valor a la cadena del man\xed en clave de econom\xeda circular."},{title:"Jard\xedn de Cronopios, un refugio para polinizadores en Ciudad Universitaria",short_name:"Jard\xedn de Cronopios, un refugio para los polinizadores",url:"https://uncinnova.unc.edu.ar/jardin-de-cronopios-un-refugio-para-polinizadores-en-ciudad-universitaria/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/PORTADAJardin-Cronopios.jpg",topic:"Conservaci\xf3n de la biodiversidad y cambio clim\xe1tico",category:"Producto, proceso o servicio innovador",ua:["Facultad de Ciencias Exactas, F\xedsicas y Naturales"],year:"2024",position:null,team:["Andrea A. Cocucci","Dana Aguilar","Julieta Badini","Mat\xedas Baranzelli","Gustavo Bertone","Antonella Costa","M. Eugenia Drewniak","Andr\xe9s Issaly","Juliana Izquierdo","Constanza Maubecin","Marcela Mor\xe9","Valeria Paiaro","Nicol\xe1s Rocamundi","Alicia S\xe9rsic","Marilina Sfardini","Florencia Soteras"],desc:"El Jard\xedn de Cronopios es un espacio educativo y de ciencia ciudadana creado en el campus de la UNC para la conservaci\xf3n de la biodiversidad urbana y la difusi\xf3n de los procesos de polinizaci\xf3n. Funciona como aula al aire libre conectada a la plataforma Inaturalist, donde especialistas de todo el mundo identifican en tiempo real las especies registradas. Desde 2021 se registraron 94 especies de plantas nativas y 194 de insectos visitantes."},{title:"Las Recicladoras | Serie audiovisual digital",short_name:"Las Recicladoras | Serie audiovisual digital",url:"https://uncinnova.unc.edu.ar/las-recicladoras-serie-audiovisual-digital/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/PORTADA-Las-Recicladoras.jpg",topic:"Conservaci\xf3n de la biodiversidad y cambio clim\xe1tico",category:"Producto, proceso o servicio innovador",ua:["Facultad de Ciencias de la Comunicaci\xf3n","Cooperativa La Victoria","Cluster Cartonero y Reciclador","El Telar","Jeta Brava"],year:"2024",position:null,team:["Ximena Cabral","Eugenia Acosta","Diego Villareal Rivarola","Marcelo C\xe1ceres","Valentina Ochi","Joaqu\xedn Villalobos Galante","Jerem\xedas Aliaga","Teresa Tissera","Jose Palacios"],desc:"\xabLas Recicladoras\xbb es una serie digital que narra, a trav\xe9s de reels, carruseles gr\xe1ficos y una composici\xf3n musical original, las experiencias de mujeres que formaron cooperativas de reciclaje en barrios vulnerables de C\xf3rdoba. Fue producida en articulaci\xf3n con colectivos culturales y organizaciones territoriales. El prop\xf3sito es visibilizar pr\xe1cticas de econom\xeda circular y promover la educaci\xf3n ambiental con lenguajes accesibles en redes sociales."},{title:"Lecheck | App para lecher\xeda clim\xe1ticamente inteligente",short_name:"App para lecher\xeda clim\xe1ticamente inteligente",url:"https://uncinnova.unc.edu.ar/lecheck-app-para-lecheria-climaticamente-inteligente/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/Lecheck-PORTADA-1024x473.jpg",topic:"Conservaci\xf3n de la biodiversidad y cambio clim\xe1tico",category:"Producto, proceso o servicio innovador",ua:["Facultad de Ciencias Agropecuarias"],year:"2024",position:null,team:["Aimar, Mar\xeda Ver\xf3nica","Negri Rodriguez, Livia","De Greef, Gustavo","Mora Mora, Mar\xeda Gabriela","La Manna, Alejandro","De Torres, Elena","Garcia, Carmen","Del Rosario, Joaquin","Rojo, Sebasti\xe1n"],desc:"Lecheck es una aplicaci\xf3n gratuita y offline que releva la implementaci\xf3n de 157 buenas pr\xe1cticas en establecimientos lecheros —sanidad, bienestar animal, gesti\xf3n ambiental, entre otras— y clasifica al tambo en cinco niveles de una escala de inteligencia clim\xe1tica. No existe otra herramienta similar que integre productividad, calidad de leche y mitigaci\xf3n del cambio clim\xe1tico en un solo lugar. Fue probada por 776 usuarios en cinco pa\xedses de Am\xe9rica Latina y el Caribe."},{title:"Plataforma de bienestar y prevenci\xf3n psicol\xf3gica asistida por IA",short_name:"Bienestar y prevenci\xf3n psicol\xf3gica asistida por IA",url:"https://uncinnova.unc.edu.ar/plataforma-de-bienestar-y-prevencion-psicologica-asistida-por-ia/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2024/05/5.1-PORTADA-1024x512.jpg",category:"Producto, proceso o servicio innovador",topic:"Salud humana",ua:["Facultad de Psicolog\xeda"],year:"2024",position:null,team:["Patricia Altamirano","Ignacio Acu\xf1a","Ra\xfal Gomez","Hebe Rigotti","Mariana Rodriguez","Narciso Perez","Guido Zanetti","Octavio Gomez"],desc:"Esta plataforma se encuentra en fase de prototipo y combina inteligencia artificial con principios de psicolog\xeda cl\xednica para monitorear el bienestar emocional de las personas usuarias, detectar recurrencias y sugerir enfoques terap\xe9uticos con respuesta casi inmediata. Es la \xfanica herramienta de este tipo en desarrollo en Argentina. Los datos relevados, con consentimiento, servir\xe1n adem\xe1s como insumo para equipos de investigaci\xf3n en salud mental."}],database_2025=[{title:"Portal de Historias Pluriling\xfces: un puente entre lenguas y culturas en la escuela primaria",short_name:"Portal de Historias Pluriling\xfces",url:"https://uncinnova.unc.edu.ar/portal-de-historias-plurilingues-un-puente-entre-lenguas-y-culturas-en-la-escuela-primaria/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/06/PORTADA-1024x812.jpg",topic:"Equidad, inclusi\xf3n y acceso al conocimiento",category:"Producto, proceso o servicio innovador",ua:["Facultad de Lenguas"],year:"2025",position:null,team:["Richard Brunel Matias, estudiantes de la asignatura, traductores y maestras de grado"],desc:"Este proyecto produce libros infantiles en siete lenguas —portugu\xe9s, espa\xf1ol, franc\xe9s, italiano, ingl\xe9s, alem\xe1n y chan\xe1— para alumnos de tercer y cuarto grado. Busca promover la educaci\xf3n pluriling\xfce en escuelas primarias p\xfablicas y privadas, a trav\xe9s de materiales de acceso libre y pr\xe1cticas de lectura trabajadas directamente en el aula."},{title:"Dise\xf1o de intervenciones organizacionales para favorecer la implementaci\xf3n de acciones de mejora continua en sistemas de gesti\xf3n de calidad",short_name:"Dise\xf1o de intervenciones organizacionales",url:"https://uncinnova.unc.edu.ar/diseno-de-intervenciones-organizacionales-para-favorecer-la-implementacion-de-acciones-de-mejora-continua-en-sistemas-de-gestion-de-calidad/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/0-PORTADA-7-1024x683.jpg",topic:"Transformaci\xf3n tecnol\xf3gica",category:"Investigaci\xf3n o desarrollo aplicable",ua:["Facultad de Ciencias Exactas, F\xedsicas y Naturales","Escuela de Perfeccionamiento en Investigaci\xf3n Operativa (EPIO)"],year:"2025",position:null,team:["Daniel Pontelli","Jos\xe9 Luis Zanazzi"],desc:"MInFRO es un modelo de intervenci\xf3n flexible y reflexivo que busca reducir las altas tasas de falla en los sistemas de gesti\xf3n de calidad. Basado en colaboraci\xf3n, pensamiento sist\xe9mico y aprendizaje organizacional, su meta es ayudar a las organizaciones a diagnosticar problemas de forma colaborativa y dise\xf1ar estrategias adaptadas a su propia realidad sociot\xe9cnica."},{title:"Preservaci\xf3n del patrimonio audiovisual a trav\xe9s de la digitalizaci\xf3n de originales f\xedlmicos",short_name:"Preservaci\xf3n del patrimonio audiovisual",url:"https://uncinnova.unc.edu.ar/preservacion-del-patrimonio-audiovisual-a-traves-de-la-digitalizacion-de-originales-filmicos/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/0-PORTADA_OPT-21-1024x769.jpg",category:"Producto, proceso o servicio innovador",topic:"Transformaci\xf3n tecnol\xf3gica",ua:["Facultad de Artes"],year:"2025",position:null,team:["Santiago Sein","Luciano Miglietta"],desc:"Este trabajo implic\xf3 la construcci\xf3n de un esc\xe1ner de 35mm, a partir de piezas recicladas y software libre, para digitalizar pel\xedculas en alta resoluci\xf3n (4K). Busca ofrecer un servicio \xfanico en el interior del pa\xeds para preservar materiales f\xedlmicos de valor hist\xf3rico, apoyar la industria audiovisual regional y evitar la dependencia de servicios concentrados en Buenos Aires."},{title:"Sensor portable y de bajo costo para monitorear el nivel de ars\xe9nico en el agua",short_name:"Sensor para monitorear ars\xe9nico en el agua",url:"https://uncinnova.unc.edu.ar/sensor-portable-y-de-bajo-costo-para-monitorear-el-nivel-de-arsenico-en-el-agua/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/0-PORTADA-edited.jpeg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Transformaci\xf3n tecnol\xf3gica",ua:["Facultad de Ciencias Qu\xedmicas","Conicet"],year:"2025",position:2,team:["Daiana F. Reartes","Marcela C. Rodr\xedguez"],desc:"Se trata de un sensor electroqu\xedmico descartable, basado en un nanoh\xedbrido de nanopart\xedculas de oro y quitosano. Es capaz de detectar arsenito en agua por debajo de los 10 ppb recomendados por la OMS. Su desarrollo busca aportar una herramienta accesible y f\xe1cil de usar para el monitoreo en zonas rurales vulnerables de Argentina, contribuyendo a la prevenci\xf3n del HACRE y enfermedades asociadas."},{title:"Bovance | Parches para administrar hormonas reproductivas en el ganado",short_name:"Bovance | Parches para el ganado",url:"https://uncinnova.unc.edu.ar/bovance-parches-para-administrar-hormonas-reproductivas-en-el-ganado/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/0-PORTADA-6-edited-scaled.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Transformaci\xf3n tecnol\xf3gica",ua:["Facultad de Ciencias Qu\xedmicas","Conicet"],year:"2025",position:null,team:["Sofia Martinez","Valentin Roldan Julian","Daniela Quinteros","Luis Ferre","Gast\xf3n Ortiz"],desc:"Esta plataforma tecnol\xf3gica reemplaza las inyecciones en los protocolos de inseminaci\xf3n artificial bovina. Se vale de parches adhesivos con microproyecciones que liberan hormonas, a trav\xe9s de la piel del animal, de forma indolora y dosificaci\xf3n precisa. Busca mejorar la tasa de pre\xf1ez, reducir el estr\xe9s animal y hacer accesible la tecnolog\xeda reproductiva avanzada a peque\xf1os y medianos productores."},{title:"Obtenci\xf3n de colorantes y antioxidantes naturales a partir de la piel de las uvas",short_name:"Colorantes y antioxidantes de piel de uva",url:"https://uncinnova.unc.edu.ar/obtencion-de-colorantes-y-antioxidantes-naturales-a-partir-de-la-piel-de-las-uvas/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/0-PORTADA-5-1024x768.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Transformaci\xf3n tecnol\xf3gica",ua:["Facultad de Ciencias Qu\xedmicas","Conicet"],year:"2025",position:null,team:["Mar\xeda Ver\xf3nica Baroni","Natalia Pigni","Renata Bence Alejandra Bustamante","F\xe9lix Condat","Mauricio Salgado Mar\xeda Paula Fattobene","Natividad Herrera Cano"],desc:"Propone transformar el orujo de uvas tintas –residuo de la industria vitivin\xedcola– en aditivos naturales multifuncionales llamados piranoantocianinas (PACN), con propiedades colorantes y antioxidantes de alta estabilidad. La intenci\xf3n es incorporarlos en productos l\xe1cteos como el yogur y la leche en polvo, en reemplazo de colorantes y antioxidantes sint\xe9ticos, mediante un proceso sostenible alineado con la econom\xeda circular."},{title:"Medicina de precisi\xf3n | Creaci\xf3n de un banco interactivo de datos cl\xednico-gen\xf3micos oncol\xf3gico",short_name:"Banco interactivo de datos cl\xednico-gen\xf3micos oncol\xf3gico",url:"https://uncinnova.unc.edu.ar/medicina-de-precision-creacion-de-un-banco-interactivo-de-datos-clinico-genomicos-oncologico/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/0-PORTADA_OPT-20-1024x796.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Salud humana",ua:["Facultad de Ciencias M\xe9dicas","Conicet"],year:"2025",position:null,team:["Mar\xeda Mercedes Stroppa","Alicia Raquel P\xe9rez de Rosas","Cintia Judith Fern\xe1ndez","Lourdes Eugenia C\xf3rdoba","Antonio Mar\xeda Garz\xf3n"],desc:"Construcci\xf3n de un banco de datos con informaci\xf3n de pacientes de C\xf3rdoba, que integre bioinform\xe1tica avanzada para identificar variantes gen\xe9ticas locales. Busca personalizar diagn\xf3sticos y tratamientos contra el c\xe1ncer para la poblaci\xf3n regional y superar la dependencia de datos provenientes de poblaciones extranjeras. Prev\xe9 capacitar a profesionales en el uso cl\xednico de esta informaci\xf3n."},{title:"Servicio de asistencia t\xe9cnica y cient\xedfica para bancos de leche humana",short_name:"Servicio para bancos de leche humana",url:"https://uncinnova.unc.edu.ar/servicio-de-asistencia-tecnica-y-cientifica-para-bancos-de-leche-humana/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/0-PORTADA_OPT-19-1024x576.jpg",topic:"Salud humana",category:"Producto, proceso o servicio innovador",ua:["Facultad de Ciencias M\xe9dicas","Facultad de Ciencias Exactas, F\xedsicas y Naturales","Conicet"],year:"2025",position:3,team:["Elio. A. Soria","Georgina N. Marchiori","Gabriel E. Beinotti","M. Valentina Cortez","Edgardo L. Calandri"],desc:"La iniciativa plantea colaborar con herramientas de an\xe1lisis bioqu\xedmico de bajo costo y aplicaciones para calcular la fortificaci\xf3n personalizada de cada lote. Este abordaje busca optimizar el uso cl\xednico de la leche donada para reci\xe9n nacidos prematuros de muy bajo peso, una estrategia a\xfan no aplicada en Argentina."},{title:"Observatorio cient\xedfico-tecnol\xf3gico para la salud materna durante el puerperio",short_name:"Observatorio para la salud materna",url:"https://uncinnova.unc.edu.ar/observatorio-cientifico-tecnologico-para-la-salud-materna-durante-el-puerperio/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/0-PORTADA_OPT-18-1024x484.jpg",topic:"Salud humana",category:"Producto, proceso o servicio innovador",ua:["Facultad de Ciencias M\xe9dicas","Conicet"],year:"2025",position:null,team:["Elio A. Soria","M. Valentina Cortez","Ana V. Scotta","Paula E. Barral","Ailin Farre"],desc:"Esta propuesta desarrolla herramientas metodol\xf3gicas —encuestas, \xedndices y dispositivos de relevamiento— para caracterizar la situaci\xf3n sanitaria, psicosocial y laboral de madres lactantes en zonas vulnerables de Argentina. Apunta a producir datos confiables que orienten pol\xedticas p\xfablicas basadas en evidencia. Es la primera iniciativa de Argentina en abordar la salud materna durante el puerperio."},{title:"M\xe9todo m\xe1s econ\xf3mico y sostenible para sintetizar Riluzol, el principal medicamento para tratar la ELA",short_name:"M\xe9todo para sintetizar Riluzol",url:"https://uncinnova.unc.edu.ar/metodo-mas-economico-y-sostenible-para-sintetizar-riluzol-el-principal-medicamento-para-tratar-la-ela/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/Grupo2_OPT-1024x576.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Salud humana",ua:["Facultad de Ciencias Qu\xedmicas","Conicet"],year:"2025",position:null,team:["Ignacio D. Lemir","Adrian A. Heredia","Juan E. Arg\xfcello","Gabriela Oksdath-Mansilla","Fabrizio Politano"],desc:"Se trata de un proceso alternativo para sintetizar Riluzol mediante activaci\xf3n fotoqu\xedmica con LEDs, flujo continuo y purificaci\xf3n integrada en l\xednea. Procura reemplazar los m\xe9todos cl\xe1sicos, que requieren altas temperaturas, largos tiempos de reacci\xf3n y costosos pasos de purificaci\xf3n. El prop\xf3sito final es reducir su costo de producci\xf3n y que el medicamento sa m\xe1s accesible para los pacientes con ELA."},{title:"Nu-Pain PHARMA | Nanotecnolog\xeda y componentes naturales para tratar el dolor cr\xf3nico",short_name:"Nu-Pain PHARMA | Tratamiento del dolor cr\xf3nico",url:"https://uncinnova.unc.edu.ar/nu-pain-pharma-nanotecnologia-y-componentes-naturales-para-tratar-el-dolor-cronico/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/0-portada-opt-1024x796.jpg",category:"Producto, proceso o servicio innovador",topic:"Salud humana",ua:["Facultad de Ciencias Qu\xedmicas","Conicet"],year:"2025",position:1,team:["Carlos Laino","Florencia Elorriaga","Maria Eugenia Olivera","Karem Arrigoni Rodr\xedguez"],desc:"Nu-Pain PHARMA es una plataforma farmac\xe9utica que combina un \xe1cido graso natural con analg\xe9sicos conocidos, formulados mediante un sistema de liberaci\xf3n autonanoemulsionable. Esto mejora la absorci\xf3n del principio activo y permite usar dosis m\xe1s peque\xf1as sin perder efectividad. La meta es ofrecer una alternativa m\xe1s segura, al tiempo que se reducen efectos secundarios como la tolerancia, la constipaci\xf3n y la dependencia que generan la morfina."},{title:"Thyrodx | Diagn\xf3stico molecular de c\xe1ncer de tiroides",short_name:"Thyrodx | Diagn\xf3stico molecular de c\xe1ncer de tiroides",url:"https://uncinnova.unc.edu.ar/thyrodx-diagnostico-molecular-de-cancer-de-tiroides/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/0-portada_OPT-17-1024x796.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Salud humana",ua:["Facultad de Ciencias Qu\xedmicas","Conicet"],year:"2025",position:null,team:["Juan Pablo Nicola","Romina Celeste Geysels"],desc:"Prueba transcript\xf3mica asistida por aprendizaje autom\xe1tico, que analiza la expresi\xf3n de 315 genes para distinguir n\xf3dulos tiroideos benignos de malignos con una precisi\xf3n del 99%. Se aplica sobre la misma muestra de punci\xf3n aspirativa, sin procedimientos adicionales. El prop\xf3sito es reducir las tiroidectom\xedas innecesarias que actualmente se practican en Argentina."},{title:"Nasalys | Diagn\xf3stico precoz de la enfermedad de Parkinson",short_name:"Nasalys | Diagn\xf3stico precoz de Parkinson",url:"https://uncinnova.unc.edu.ar/nasalys-diagnostico-precoz-de-la-enfermedad-de-parkinson/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/Captura-de-pantalla-2024-11-20-101707.png",category:"Producto, proceso o servicio innovador",topic:"Salud humana",ua:["Facultad de Ciencias Exactas, F\xedsicas y Naturales"],year:"2025",position:3,team:["Gastaldi Pilar","Huber Julieta","Sosa Josefina","Villarroel Ana Delia Sofia"],desc:"Nasalys automatiza el test olfativo para la detecci\xf3n temprana del Parkinson. Incorpora un soporte ergon\xf3mico que mantiene distancia constante entre nariz y l\xe1piz, y una botonera conectada a computadora para registrar respuestas autom\xe1ticamente. El prop\xf3sito es contar con una herramienta higi\xe9nica, estandarizada y apta para campa\xf1as de detecci\xf3n masiva, superando las limitaciones del test convencional."},{title:"Estimaci\xf3n del tiempo de fallecimiento a partir del an\xe1lisis de la pulpa dentaria humana",short_name:"Estimaci\xf3n del tiempo de fallecimiento a partir de la pulpa dentaria",url:"https://uncinnova.unc.edu.ar/estimacion-del-tiempo-de-fallecimiento-a-partir-del-analisis-de-la-pulpa-dentaria-humana/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/0-PORTADA_OPT-14-1024x846.jpg",topic:"Salud humana",category:"Producto, proceso o servicio innovador",ua:["Facultad de Ciencias M\xe9dicas","Instituto de Biolog\xeda Celular (IBC) – FCM – UNC"],year:"2025",position:null,team:["Florencia Granton","Eugenia Pasqualini","Mercedes Stroppa","Nidia Modesti"],desc:"Este proyecto analiza microARNs presentes en la pulpa dentaria de personas fallecidas para estimar el intervalo postmortem. A diferencia de los m\xe9todos tradicionales, aplicables solo en las primeras horas o d\xedas, esta t\xe9cnica funciona en rangos de tiempo m\xe1s amplios y en condiciones avanzadas de descomposici\xf3n."},{title:"Biomaterial a base de gelatina y curcumina para tratar heridas cr\xf3nicas infectadas",short_name:"Biomaterial para heridas cr\xf3nicas infectadas",url:"https://uncinnova.unc.edu.ar/biomaterial-a-base-de-gelatina-y-curcumina-para-tratar-heridas-cronicas-infectadas/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/0-PORTADA_OPT-13-1024x568.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Salud humana",ua:["Facultad de Ciencias Exactas, F\xedsicas y Naturales","Conicet"],year:"2025",position:null,team:["Milagros Stanley","Mariana Cid","Nancy Salvatierra","Tom\xe1s C. Tempesti","Romina Com\xedn"],desc:"Consiste en el desarrollo de un ap\xf3sito de nanofibras de gelatina con curcumina, producido por electrohilado y dise\xf1ado para la Terapia Fotodin\xe1mica Antimicrobiana. Al activarse con luz azul, libera especies reactivas de ox\xedgeno que eliminan bacterias sin generar resistencia microbiana. Ofrece una alternativa eficaz y sustentable a los antibi\xf3ticos en el tratamiento de heridas cr\xf3nicas infectadas."},{title:"Papi-YA | Papillas para beb\xe9s a base de cereales y legumbres",short_name:"Papi-YA | Papillas a base de cereales y legumbres",url:"https://uncinnova.unc.edu.ar/papi-ya-papillas-para-bebes-a-base-de-cereales-y-legumbres/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/0-PORTADA_OPT-12-1024x768.jpg",category:"Investigaci\xf3n o desarrollo aplicable",topic:"Salud humana",ua:["Conicet"],year:"2025",position:null,team:["Rodriguez Marianela","Moine Luciana","Guzman Federico","Bustos Mariela"],desc:"Papi-YA formula papillas infantiles con cereales y legumbres tratadas t\xe9rmicamente, fortificadas con hierro, zinc y vitamina C. Est\xe1n adaptadas a tres condiciones nutricionales: normopeso, bajo peso y sobrepeso. Las papillas constituyen una alternativa accesible y cient\xedficamente validada a los productos comerciales del mercado, que suelen tener bajo aporte proteico y exceso de sal y az\xfacar."},{title:"ALINA Tracci\xf3n | Dispositivo para adolescentes con escoliosis idiop\xe1tica",short_name:"Dispositivo para adolescentes con escoliosis idiop\xe1tica",url:"https://uncinnova.unc.edu.ar/alina-traccion-dispositivo-para-adolescentes-con-escoliosis-idiopatica/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/0-PORTADA_OPT-11-1024x576.jpg",category:"Producto, proceso o servicio innovador",topic:"Salud humana",ua:["Facultad de Arquitectura, Urbanismo y Dise\xf1o"],year:"2025",position:null,team:["Bonis, Axel Alexander","Mart\xedn, \xc1lvaro Enrique","Trippel, Mariana"],desc:"Sistema de halo tracci\xf3n prequir\xfargico para adolescentes con escoliosis grave. A diferencia de los dispositivos disponibles en el pa\xeds, permite moverse, levantarse y caminar con autonom\xeda dentro del hogar. Incorpora adem\xe1s una est\xe9tica menos invasiva para reducir el impacto psicol\xf3gico del tratamiento en pacientes y familias."},{title:"Estetoscopio electr\xf3nico con inteligencia artificial para auscultaciones card\xedacas",short_name:"Estetoscopio electr\xf3nico con IA",url:"https://uncinnova.unc.edu.ar/estetoscopio-electronico-con-inteligencia-artificial-para-auscultaciones-cardiacas/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/0-PORTADA_OPT-10-1024x733.jpg",category:"Producto, proceso o servicio innovador",topic:"Salud humana",ua:["Facultad de Ciencias Exactas, F\xedsicas y Naturales"],year:"2025",position:null,team:["Ezequiel Nicol\xe1s Barreto","Elda Rosal\xeda Bertello"],desc:"Este dispositivo cuenta con un software de inteligencia artificial y redes neuronales para clasificar sonidos card\xedacos. Busca reducir la subjetividad de la auscultaci\xf3n tradicional, cuya precisi\xf3n var\xeda dr\xe1sticamente seg\xfan la experiencia del profesional. Resulta especialmente \xfatil para m\xe9dicos en formaci\xf3n o con hipoacusia."},{title:"Bast\xf3n inteligente para personas con ceguera",short_name:"Bast\xf3n inteligente para personas con ceguera",url:"https://uncinnova.unc.edu.ar/baston-inteligente-para-personas-con-ceguera/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/0-PORTADA_OPT-8-1024x657.jpg",topic:"Equidad, inclusi\xf3n y acceso al conocimiento",category:"Producto, proceso o servicio innovador",ua:["Facultad de Arquitectura, Urbanismo y Dise\xf1o"],year:"2025",position:null,team:["Anabella Peppino","Cristian Alejandro Simoncini Reyes"],desc:"El bast\xf3n cuenta con sensores ultras\xf3nicos que alertan mediante vibraciones cuando la persona se acerca a obst\xe1culos elevados, como ramas y carteles. Incorpora, adem\xe1s, un giroscopio para corregir desviaciones de trayectoria en tiempo real. Procura ampliar las posibilidades de desplazamiento aut\xf3nomo y seguro, a un costo accesible y con dise\xf1o ergon\xf3mico."},{title:"Una tienda accesible para construir comunidades inclusivas",short_name:"Tienda accesible para construir comunidades",url:"https://uncinnova.unc.edu.ar/una-tienda-accesible-para-construir-comunidades-inclusivas/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/0-PORTADA_OPT-7-1024x768.jpg",topic:"Equidad, inclusi\xf3n y acceso al conocimiento",category:"Producto, proceso o servicio innovador",ua:["Facultad de Ciencias M\xe9dicas"],year:"2025",position:null,team:["Camila Belen Quiroga","Docentes formados en los oficios de cer\xe1mica, estampado, sublimaci\xf3n e impresi\xf3n en 3D, y profesionales vinculados al abordaje y acompa\xf1amiento de personas con discapacidad."],desc:"El proyecto est\xe1 radicado Salsipuedes, una localidad del interior de C\xf3rdoba. Brinda formaci\xf3n en oficios como cer\xe1mica, impresi\xf3n 3D y estampado a j\xf3venes y adultos con discapacidad, una franja etaria que est\xe1 fuera del alcance de las pol\xedticas locales de inclusi\xf3n. La iniciativa apunta a que fabriquen y comercialicen sus propios productos. De esa manera, promueve su autonom\xeda econ\xf3mica, su inserci\xf3n laboral y su participaci\xf3n plena en la comunidad."},{title:"Term\xf3metro audible para personas ciegas",short_name:"Term\xf3metro para personas ciegas",url:"https://uncinnova.unc.edu.ar/termometro-audible-para-personas-ciegas/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/0-PORTADA-2-edited.jpg",topic:"Equidad, inclusi\xf3n y acceso al conocimiento",category:"Producto, proceso o servicio innovador",ua:["Facultad de Ciencias Exactas, F\xedsicas y Naturales"],year:"2025",position:null,team:["Ocampo, Lautaro Gabriel","Molina, Mat\xedas","Zavaley, Jos\xe9 Mar\xeda","Salgado, Valentin","Singh, Ignacio"],desc:"El term\xf3metro es desarrollado en colaboraci\xf3n con la Fundaci\xf3n Gaude. Anuncia la temperatura en voz alta e incluye pantalla para personas con baja visi\xf3n. Dispositivos similares no se comercializan en Argentina y los importados son costosos. Se trata de una soluci\xf3n accesible, econ\xf3mica y de fabricaci\xf3n local que aporta mayor autonom\xeda a personas con discapacidad visual."},{title:"Sensus Iter | Sistema para detectar obst\xe1culos en el camino de personas con discapacidad visual",short_name:"Detector de obst\xe1culos para personas con discapacidad visual",url:"https://uncinnova.unc.edu.ar/sensus-iter-sistema-para-detectar-obstaculos-en-el-camino-de-personas-con-discapacidad-visual/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/0-PORTADA-1-1024x768.jpg",topic:"Equidad, inclusi\xf3n y acceso al conocimiento",category:"Producto, proceso o servicio innovador",ua:["Facultad de Ciencias Exactas, F\xedsicas y Naturales","Extensi\xf3n universitaria , Programa de Innovaci\xf3n y Desarrollo tecnol\xf3gico"],year:"2025",position:null,team:["Gutierrez Andr\xe9s Benjam\xedn","Pe\xf1alva Miqueas Rafael","Pereira Petruele Antonio Jes\xfas"],desc:"Se trata de una pechera con sensores ultras\xf3nicos que detecta obst\xe1culos y alerta mediante se\xf1ales sonoras, complementando al bast\xf3n tradicional. Desarrollada con Arduino y componentes de bajo costo, apunta a aumentar la seguridad y autonom\xeda de personas con discapacidad visual durante sus desplazamientos, con la ventaja adicional de ser escalable y de f\xe1cil reparaci\xf3n."},{title:"GULICH Node | Sistema de geodatos abierto a la comunidad",short_name:"Geodatos abiertos a la comunidad",url:"https://uncinnova.unc.edu.ar/gulich-node-sistema-de-geodatos-abierto-a-la-comunidad/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/0-PORTADA_OPT-6-1024x668.jpg",topic:"Equidad, inclusi\xf3n y acceso al conocimiento",category:"Producto, proceso o servicio innovador",ua:["Instituto Gulich"],year:"2025",position:null,team:["Fernanda Garc\xeda Ferreyra","Rodrigo Chani","Cristhian Escobares","Carlos Salinas","Luis Cruz","Guadalupe Escalante","Silvana Palavecino","Manuel Zeballos","Ivanna Tropper","Helena Sangroniz","Camilo Barra","Elisabet Benitez","Julieta Motter","Bernardita Rivera","Marina Compagnucci","Ver\xf3nica Sch\xfcler","Aldana Bini","Ezequiel De Luca","Miguel Rodr\xedguez Maiztegui","Pablo Zader","Gast\xf3n Gonz\xe1lez Kriegel"],desc:"Es una plataforma de c\xf3digo abierto que permite visualizar, descargar e interactuar con datos geoespaciales sobre variables ambientales y socioecon\xf3micas de Argentina. Surge para democratizar el acceso a resultados de tesis de maestr\xeda y doctorado del Instituto Gulich. Su finalidad es ampliar el impacto de ese conocimiento hacia los sectores social, productivo, cient\xedfico y educativo."},{title:"Servicio de traducci\xf3n y terminolog\xeda para tramitar patentes a nivel global",short_name:"Servicio de traducci\xf3n para tramitar patentes",url:"https://uncinnova.unc.edu.ar/servicio-de-traduccion-y-terminologia-para-tramitar-patentes-a-nivel-global/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/0-PORTADA-1024x682.jpg",topic:"Equidad, inclusi\xf3n y acceso al conocimiento",category:"Producto, proceso o servicio innovador",ua:["Facultad de Lenguas"],year:"2025",position:3,team:["Lorena Guadalupe Baudo","Gabriela Fernanda Lorenzo Ayl\xe9n Bailone-Bringas","Mar\xeda Luz L\xf3pez Joaqu\xedn Gnavi","Alex Ontiveros"],desc:"Este proyecto de la Facultad de Lenguas ofrece un servicio terminol\xf3gico especializado a equipos innovadores de la UNC para ayudarlos a documentar y tramitar sus patentes en ingl\xe9s con precisi\xf3n t\xe9cnica. Se basa en la colaboraci\xf3n acad\xe9mica con la OMPI, activa desde 2018, y en normas ISO internacionales."},{title:"Bio productos 5.0 | Econom\xeda circular con residuos de la industria textil",short_name:"Econom\xeda circular con residuos de la industria textil",url:"https://uncinnova.unc.edu.ar/bio-productos-5-0-economia-circular-con-residuos-de-la-industria-textil/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/IMG_20240218_100050_OPT-1024x576.jpg",topic:"Conservaci\xf3n de la biodiversidad y cambio clim\xe1tico",category:"Producto, proceso o servicio innovador",ua:["Facultad de Arquitectura, Urbanismo y Dise\xf1o"],year:"2025",position:null,team:["Fernando Corcoba"],desc:"Bio Productos 5.0 transforma sobrantes de corte textil en luminarias y mobiliario, aglomer\xe1ndolos con almid\xf3n, agua, glicerina y retardante de fuego. La clave est\xe1 en la reversibilidad del proceso: al disolver el aglomerante, el material puede recuperarse y reutilizarse al final de su vida \xfatil. El prop\xf3sito es reducir el uso de maderas y pl\xe1sticos mediante un ciclo productivo de impacto ambiental m\xednimo."},{title:"Pel\xedculas y coberturas comestibles a partir de expeller de canola y aditivos naturales",short_name:"Coberturas comestibles a partir de expeller de canola",url:"https://uncinnova.unc.edu.ar/peliculas-y-coberturas-comestibles-a-partir-de-expeller-de-canola-y-aditivos-naturales/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/0-PORTDA-1024x491.jpg",topic:"Bioeconom\xeda",category:"Investigaci\xf3n o desarrollo aplicable",ua:["Facultad de Ciencias Agropecuarias","Conicet"],year:"2025",position:null,team:["Cecilia Gabriela Riveros","Valeria Nepote","Patricia Raquel Quiroga","Leonardo Gabriel Vera","Melisa Fushimi"],desc:"Este proyecto propone desarrollar materiales biodegradables para la conservaci\xf3n de alimentos.  La meta es generar coberturas y pel\xedculas comestibles a partir de expeller de canola, combinado con aditivos naturales como extractos polifen\xf3licos y aceite de oliva. Estas coberturas no s\xf3lo permitir\xe1n mejorar la conservaci\xf3n de alimentos, sino prolongar su vida \xfatil y reducir el uso de envases derivados del petr\xf3leo."},{title:"Microc\xe1psulas de productos naturales para controlar bacterias que afectan a cultivos",short_name:"Microc\xe1psulas para controlar bacterias",url:"https://uncinnova.unc.edu.ar/microcapsulas-de-productos-naturales-para-controlar-bacterias-que-afectan-a-cultivos/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/0-POTADA_OPT-1024x436.jpg",topic:"Bioeconom\xeda",category:"Investigaci\xf3n o desarrollo aplicable",ua:["Facultad de Ciencias Agropecuarias"],year:"2025",position:null,team:["Mar\xeda Cecilia Prieto","Nelson Rub\xe9n Grosso"],desc:"Busca desarrollar nuevos compuestos antibacterianos a partir de aceites esenciales y extractos vegetales obtenidos de plantas nativas y cultivadas. Esos compuestos bioactivos son analizados en ensayos de laboratorio para determinar su efectividad contra las bacterias fitopat\xf3genas. Aquellos con mayor potencial, son encapsulados en una cubierta microsc\xf3pica para protegerlos de la degradaci\xf3n y permitir su liberaci\xf3n gradual."},{title:"Producci\xf3n de enzima lacasa para mejorar masas de harinas alternativas (quinoa, amaranto o trigo sarraceno)",short_name:"Producci\xf3n de enzima lacasa",url:"https://uncinnova.unc.edu.ar/produccion-de-enzima-lacasa-para-mejorar-masas-de-harinas-alternativas-quinoa-amaranto-o-trigo-sarraceno/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/0-PORTADA_OPT-4-1024x830.jpg",topic:"Bioeconom\xeda",category:"Investigaci\xf3n o desarrollo aplicable",ua:["Facultad de Ciencias Agropecuarias"],year:"2025",position:3,team:["Edgardo Calandri","Pilar Serbent","Eugenia Rodr\xedguez Emiliano Sottile","Karina Abbes","Graciela Pergassere"],desc:"Propone llevar la producci\xf3n de lacasa f\xfangica –ya validada en laboratorio– a nivel piloto. El proceso consiste en la adaptaci\xf3n de condiciones como pH, temperatura y aireaci\xf3n para maximizar su rendimiento en un entorno controlado. El prop\xf3sito es obtener cantidades suficientes para concentrar, caracterizar y aplicarla en harinas alternativas y de baja fuerza. La meta \xfaltima es desarrollar un proceso local, eficiente y escalable de producci\xf3n."},{title:"OPTIMACQUA | Ciencia de datos aplicada a la optimizaci\xf3n del riego en agricultura",short_name:"OPTIMACQUA | Optimizaci\xf3n del riego en agricultura",url:"https://uncinnova.unc.edu.ar/optimacqua-ciencia-de-datos-aplicada-a-la-optimizacion-del-riego-en-agricultura/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/Mesa-de-trabajo-1-1-1024x480.png",topic:"Bioeconom\xeda",category:"Producto, proceso o servicio innovador",ua:["Facultad de Ciencias Agropecuarias"],year:"2025",position:2,team:["Ignacio Pascual","Ezequiel de Luca","Emiliano de Luca","Federico Machado","Mauro Lopez Gregori."],desc:"OPTIMACQUA es una aplicaci\xf3n que opera en la nube. Integra relevamientos de la red de estaciones meteorol\xf3gicas, im\xe1genes satelitales e informaci\xf3n del campo, el suelo y la humedad, entre otros. Con esos datos, algoritmos entrenados con machine learning generan recomendaciones sobre el momento \xf3ptimo para regar y la cantidad de agua que debe recibir el cultivo durante los d\xedas subsiguientes."},{title:"Biopol\xedmero producidos por cianobacterias de la Ant\xe1rtida para reemplazar los pl\xe1sticos tradicionales",short_name:"Biopol\xedmero para reemplazar pl\xe1sticos tradicionales",url:"https://uncinnova.unc.edu.ar/biopolimero-producidos-por-cianobacterias-de-la-antartida-para-reemplazar-los-plasticos-tradicionales/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/Mesa-de-trabajo-1-1024x682.png",topic:"Bioeconom\xeda",category:"Investigaci\xf3n o desarrollo aplicable",ua:["Facultad de Ciencias Exactas, F\xedsicas y Naturales","Conicet"],year:"2025",position:null,team:["Estela Cecilia Mlewski","Edith Filippini","Natalia Domig","Josefina Casaux","Karina Lecomte"],desc:"Esta iniciativa planea utilizar cianobacterias extrem\xf3filas de la Ant\xe1rtida para producir polihidroxibutirato (PHB), un biopl\xe1stico que no deja residuos t\xf3xicos al descomponerse. A diferencia de otros m\xe9todos, el uso de esos microorganismos no requiere condiciones controladas costosas ni una infraestructura especial."},{title:"BIOSOLVPEC | Biopel\xedculas para la conservaci\xf3n de alimentos",short_name:"Biopel\xedculas para la conservaci\xf3n de alimentos",url:"https://uncinnova.unc.edu.ar/biosolvpec-biopeliculas-para-la-conservacion-de-alimentos/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/0-PORTADA_OPT-3-1024x585.jpg",topic:"Bioeconom\xeda",category:"Investigaci\xf3n o desarrollo aplicable",ua:["Facultad de Ciencias Agropecuarias","Conicet"],year:"2025",position:null,team:["Pablo Agust\xedn Mercadal","Agust\xedn Gonz\xe1lez","Marianela Zoratti","Paola Gim\xe9nez"],desc:"Las biopel\xedculas ser\xe1n elaboradas a partir de pectina, que se obtiene de residuos frutales, como c\xe1scaras de manzana y c\xedtricos. A ella se le agregar\xe1n solventes eut\xe9cticos, que mejoran su resistencia, flexibilidad y capacidad de barrera. Adem\xe1s a\xf1aden propiedades antioxidantes y antimicrobianas que prolongan la vida \xfatil de los alimentos."},{title:"Electrolizador para producir hidr\xf3geno verde",short_name:"H2-GENEL | Producci\xf3n sustentable de hidr\xf3geno verde",url:"https://uncinnova.unc.edu.ar/h2-genel-electrolizador-para-la-produccion-sustentable-de-hidrogeno-verde/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/0-PORTADA_OPT-2-1024x461.jpg",topic:"Bioeconom\xeda",category:"Producto, proceso o servicio innovador",ua:["Facultad de Ciencias Qu\xedmicas","Conicet"],year:"2025",position:null,team:["Marias Olmi","Melisa Gomez","Gabriel Correa Perelmuter","Gabriela Lacconi","Esteban Franceschini"],desc:"Propone el dise\xf1o y construcci\xf3n de un electrolizador alcalino con insumos y materiales de origen nacional. La meta es lograr un dispositivo con est\xe1ndares de eficiencia y seguridad similares a los equipos comerciales importados, pero a menor costo, con dise\xf1o modular y abierto. Se busca fomentar la soberan\xeda tecnol\xf3gica, fortalecer una cadena de valor nacional para la energ\xeda limpia y contribuir a la descarbonizaci\xf3n del pa\xeds."},{title:"Mallas de bajo costo para la producci\xf3n de hidr\xf3geno verde",short_name:"Mallas para producir hidr\xf3geno verde",url:"https://uncinnova.unc.edu.ar/mallas-de-bajo-costo-para-la-produccion-de-hidrogeno-verde/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/0-PORTADA_OPT-1-edited-1024x576.jpg",topic:"Bioeconom\xeda",category:"Investigaci\xf3n o desarrollo aplicable",ua:["Facultad de Ciencias Qu\xedmicas","Conicet"],year:"2025",position:1,team:["Katerina A. Berk Moreno","Roc\xedo A. Caraballo","Gabriela I. Lacconi","Esteban A. Franceschini","Federico Fioravanti","Victoria Benavente Llorente"],desc:"Este proyecto plantea utilizar mallas de acero recubiertas con n\xedquel poroso como alternativa local a las costosas mallas de n\xedquel puro, que actualmente deben ser importadas. Las mallas son un insumo esencial para el funcionamiento de los electrolizadores. El recubrimiento propuesto se obtiene con t\xe9cnicas sencillas y escalables (electrodeposici\xf3n), los cual reduce el costo de manera significativa. Este abordaje se plantea contribuir al desarrollo de una cadena de valor local para la producci\xf3n de hidr\xf3geno verde."},{title:"Sistema para la fertilizaci\xf3n inteligente de los cultivos de ma\xedz",short_name:"Fertilizaci\xf3n inteligente de los cultivos",url:"https://uncinnova.unc.edu.ar/sistema-para-la-fertilizacion-inteligente-de-los-cultivos-de-maiz/",img:"https://uncinnova.unc.edu.ar/wp-content/uploads/sites/54/sites/54/2025/05/0-PORTADA_OPT-edited-1024x576.jpg",topic:"Bioeconom\xeda",category:"Investigaci\xf3n o desarrollo aplicable",ua:["Facultad de Ciencias Exactas, F\xedsicas y Naturales","SECyT UNC"],year:"2025",position:null,team:["Ra\xfal E. Ahumada","Pablo Arranz"],desc:"Este proyecto desarroll\xf3 el primer modelo matem\xe1tico para ma\xedz que analiza la interacci\xf3n entre nitr\xf3geno y f\xf3sforo en simult\xe1neo, en lugar de tratarlos por separado como hacen los m\xe9todos tradicionales. Desde una interfaz web gratuita, el productor carga datos de su suelo y obtiene recomendaciones precisas de fertilizaci\xf3n. El sistema demostr\xf3 ser un 28% m\xe1s preciso, aumentar el rendimiento hasta un 15% y reducir el gasto en fertilizantes hasta un 20%."}];